INSERT INTO public.photos VALUES (21587, 'Calle Fernando el Cat‚îú‚îÇlico c.1923', 'Puesto de venta ambulante en la calle de Fernando el Cat‚îú‚îÇlico, con el fondo del seminario metropolitano. Al fondo, el paseo del Ebro.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65581400, -0.87622500, '0101000020E6100000D200DE02090AECBF252191B6F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24787073652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24787073652.webp', 'https://www.flickr.com/photos/zaragozaantigua/24787073652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21595, 'Calle Don Jaime c.1920', 'Calle de Don Jaime I, en su confluencia con la del Pilar (al fondo a la izquierda). Tras el caballero de primer plano, la Lonja. A la izquierda, comercio de recuerdos neoclasicista. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878756026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878756026.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878756026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21649, 'Calle del Pilar 1923', 'In‚îú¬Ædita imagen capturada en la calle del Pilar, esquina con la plaza de la Seo y la calle de Fernando el Cat‚îú‚îÇlico, que hacia el fondo y a la derecha conduce al paseo del Ebro y el puente de Piedra. En primer t‚îú¬Ærmino, una vendedora ambulante de frutas y verduras, entre las que destacan granadas de temporada. Frente a ella, el "brasero" o solanera de la Lonja, donde se arrima hasta una pareja de urbanos junto a otro puesto ambulante.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65555100, -0.87670600, '0101000020E61000008C9FC6BDF90DECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51371172171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51371172171.webp', 'https://www.flickr.com/photos/zaragozaantigua/51371172171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21659, 'Plaza de La Seo, c.1920', 'Imagen tomada en la plaza de La Seo, donde destaca su isleta de verdor centrada en la Fuente de la Samaritana y la ingrata presencia de su denostado mingitorio. Hacia el fondo y tras la calle de Fernando el Cat‚îú‚îÇlico, ensanche de la calle del Pilar.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53605982143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53605982143.webp', 'https://www.flickr.com/photos/zaragozaantigua/53605982143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21740, 'Lonja 1933', 'Imagen de conjunto de la antigua Lonja y Casa de la Moneda de la ciudad, capturada en cierta altura desde el Seminario Diocesano. En primer plano, las traseras del edificio convertidas en despejada zona de jardines y disfrute ciudadano, tras derribo de las antiguas Casas de la Ciudad. A la izquierda, la calle Fernando el Cat‚îú‚îÇlico que conduce a la plaza de la Seo. A la derecha, la que fuera Posada del Rey, junto al palacio de los marqueses de Ayerbe, y el Pilar. Fuente visual: "Revista Espa‚îú‚ñíola de Turismo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21776602559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21776602559.webp', 'https://www.flickr.com/photos/zaragozaantigua/21776602559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21765, 'Plaza La Seo 1932', 'Plaza de la Seo desde la calle del Pilar. A la izquierda, la Lonja. Al fondo, el Arco del Arzobispo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22621963413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22621963413.webp', 'https://www.flickr.com/photos/zaragozaantigua/22621963413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21767, 'Jardines de La Lonja 1932', 'Jardines de la Lonja junto al paseo de la Ribera. Al fondo, el palacio de los marqueses de Ayerbe y el Pilar. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622365053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622365053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622365053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21884, 'La Lonja 1938', 'Imagen capturada en los jardines traseros de la Lonja, donde los posados con palomas se hab‚îú¬°an convertido en una antropol‚îú‚îÇgica tradici‚îú‚îÇn. En este caso, el objetivo se centra, entre bancas palomas, en uno de los aviadores alemanes de la Legi‚îú‚îÇn C‚îú‚îÇndor radicados en la ciudad y con servicio en el grupo de bombardeo K/88 establecido en el aer‚îú‚îÇdromo Sanjurjo. Por el paseo del Ebro, al fondo, coincide concurrido tr‚îú√≠fico de caballer‚îú¬°a, carro, y veh‚îú¬°culo a motor. A la derecha, quiosco de los jardines.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49596274877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49596274877.webp', 'https://www.flickr.com/photos/zaragozaantigua/49596274877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21897, 'Calle del Pilar c.1934', 'Imagen capturada en la calle del Pilar con el objetivo dirigido hacia la plaza de La Seo, donde destaca a la izquierda el arco del Arzobispo. Unos guardias de asalto caminan junto a la Lonja en direcci‚îú‚îÇn a la plaza del Pilar. A la derecha, el singular establecimiento "El Pilar", multitienda de objetos art‚îú¬°sticos de recuerdo, objetos de escritorio y ornamentos religiosos.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65572700, -0.87686700, '0101000020E6100000D921FE614B0FECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50945685863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50945685863.webp', 'https://www.flickr.com/photos/zaragozaantigua/50945685863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21925, 'Ribera del Pilar c.1940', 'AHPZ-Archivo Fotogr‚îú√≠fico Jos‚îú¬Æ Galiay, (SF). El Pilar desde la ribera del Ebro.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65629600, -0.87643300, '0101000020E61000004C530438BD0BECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700887978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700887978.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700887978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22202, 'Xim‚îú¬Ænez de Emb‚îú‚ïën 1958', 'Imagen de la calle de Tom‚îú√≠s Xim‚îú¬Ænez de Emb‚îú‚ïën capturada desde la ampliada plaza del Pilar. A la izquierda, el edificio en construcci‚îú‚îÇn de la nueva Casa Consistorial. A la derecha, la Lonja. Al fondo, el paseo del Ebro, y el fondo esc‚îú¬Ænico de la margen izquierda. Fuente visual: archivo Heraldo de Arag‚îú‚îÇn, en "Padre Ebro. El r‚îú¬°o Ebro y el siglo XX".', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65590600, -0.87700600, '0101000020E610000032AA0CE36E10ECBF06A051BAF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33823491101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33823491101.webp', 'https://www.flickr.com/photos/zaragozaantigua/33823491101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22219, 'Plaza del Pilar 1954', 'Imagen capturada desde la torre de la Seo, posiblemente a la altura de su segundo cuerpo en ladrillo, con una buena perspectiva de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca, para convertirse en escenario de multitudinarias ceremonias de reafirmaci‚îú‚îÇn del r‚îú¬Ægimen franquista y su ‚îú¬°ntima vinculaci‚îú‚îÇn con la iglesia cat‚îú‚îÇlica. En primer t‚îú¬Ærmino, breve visual de la arbolada plaza de La Seo y de la calle de Don Jaime I. A la derecha, Lonja y andamios de obra de la nueva Casa Consistorial, cuyo avanzado desarrollo en la fachada recayente a la plaza se deb‚îú¬°a al Congreso Mariano de este a‚îú‚ñío, para dar una imagen esc‚îú¬Ænica de falso acabado ante los miles de congresistas venidos de fuera de la ciudad. Del templo del Pilar, detr‚îú√≠s, despuntan las obras de las dos nuevas torres ribere‚îú‚ñías, patrocinadas econ‚îú‚îÇmicamente por Francisco Urzaiz y Leonor Sala, cuando ambas todav‚îú¬°a ascend‚îú¬°an en sinton‚îú¬°a, luego rota por el mayor desarrollo de la torre noroeste en su finalizaci‚îú‚îÇn.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65552700, -0.87688900, '0101000020E6100000CE1B2785790FECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48300029697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48300029697.webp', 'https://www.flickr.com/photos/zaragozaantigua/48300029697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22236, 'Plaza del Pilar 1954', 'Imagen capturada desde la altura del inmueble chaflanero entre la plaza de La Seo y la calle de Don Jaime I, con una vista centrada en la plaza del Pilar. Por la derecha y sobre el firme se destaca la alargada sombra de la torre de la Seo. Tras ella, la Lonja y la nueva Casa Consistorial haciendo las funciones de una "aldea Potemkim": la fachada recayente a la plaza ha sido terminada a marchas forzadas para el Congreso Mariano celebrado en este entorno, mientras el resto segu‚îú¬°a en obras. A su lado, el templo del Pilar con las torres de la ribera en construcci‚îú‚îÇn. Al fondo, resplandece al sol el reci‚îú¬Æn terminado "Altar de la Patria" o "Monumento a los h‚îú¬Æroes y m‚îú√≠rtires de Zaragoza. Ca‚îú¬°dos en la Cruzada de Liberaci‚îú‚îÇn 1936-1939".', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50682145953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50682145953.webp', 'https://www.flickr.com/photos/zaragozaantigua/50682145953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22267, 'Cine Pax 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Los 60 arrancaban en la ciudad con la apertura de varios Cines (no "salas" de cine, Cines), porque en Espa‚îú‚ñía la televisi‚îú‚îÇn a‚îú‚ïën no amenazaba con matar a la estrella de la radio, y del cine. As‚îú¬°, en 1961 abrieron sus puertas el "Dux" y el "Roxy", dos cines "de barrio", en San Jos‚îú¬Æ y Montemol‚îú¬°n, respectivamente. En 1963 vio la luz el "Pax", en la Plaza de la Seo n‚î¨‚ïë 6, con capacidad de 600 personas, y orientado hacia un tipo de cine entre lo familiar, y lo tolerado-para-todos-los-p‚îú‚ïëblicos. Ser‚îú√≠ clausurado en 1984, junto con otros 15 cines de la ciudad (entre ellos, todos los cines de barrio). En la imagen, animada fila para el "Pax" cuando proyectaba el norteamericano filme "Rosie!", al que la peculiar espa‚îú‚ñíolizaci‚îú‚îÇn del t‚îú¬°tulo le hab‚îú¬°a a‚îú‚ñíadido la coletilla "Una se‚îú‚ñíora riqu‚îú¬°sima", una comedia donde aparec‚îú¬°a la angelical Sandra Dee, la misma que una d‚îú¬Æcada despu‚îú¬Æs ser‚îú¬°a parodiada con ca‚îú‚ïëstica gracia en "Grease".', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65551900, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850753965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850753965.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850753965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22285, 'Riada de 1961', 'Foto Heraldo de Arag‚îú‚îÇn, 1961. La riada del Ebro a su paso por el puente de Piedra de Zaragoza en enero de 1961, la mayor del siglo XX. Fuente: www.heraldo.es/noticias/especiales/2014/07/11/grandes_ria...', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65625900, -0.87638600, '0101000020E61000001F8315A75A0BECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161139382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161139382.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161139382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22647, 'La Lonja 1970', 'Celebraci‚îú‚îÇn del concurso Maja Internacional en el palacio de la Lonja de Zaragoza, el 11 de mayo de 1970. Este certamen tuvo su sede en la ciudad en diez ocasiones, entre 1966 y 1975. En 1970 result‚îú‚îÇ ganadora la representante de Chile, Mar‚îú¬°a Isabel P‚îú¬Ærez (quinta por la izquierda). Fuente: www.chileancharm.com/', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20928761109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20928761109.webp', 'https://www.flickr.com/photos/zaragozaantigua/20928761109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23173, 'Antonio L‚îú‚îÇpez 2009', 'Imagen del pintor manchego Antonio L‚îú‚îÇpez Garc‚îú¬°a en la plaza del Pilar, durante una aparici‚îú‚îÇn p‚îú‚ïëblica en la que se ofreci‚îú‚îÇ al Cabildo del Pilar para pintar una b‚îú‚îÇveda del templo, y esculpir un bulto redondo relacionado. A la izquierda del pintor, el cenotafio de Goya que antes estuviera en el Rinc‚îú‚îÇn de Goya del Parque de Buenavista. Tras retrasos y contingencias varias, el 11 de enero de 2016, pocos d‚îú¬°as despu‚îú¬Æs del cumplea‚îú‚ñíos 80 de este pintor, fue presentado, mediante una proyecci‚îú‚îÇn sobre la c‚îú‚ïëpula objeto de la intervenci‚îú‚îÇn, el boceto con la imagen del rostro de una mujer que simbolizaba a la Virgen Mar‚îú¬°a. El car‚îú√≠cter hiperrealista de la pintura propuesta, en l‚îú¬°nea con el reconocido estilo del autor, y la ausencia de los tradicionales s‚îú¬°mbolos y atributos marianos, llevaron al Cabildo a descartar el proyecto por no adecuado, o lejano de la oficial iconodul‚îú¬°a mariana. Fuente visual: foto Jos‚îú¬Æ Miguel Marco, en www.tribunadelamoraleja.com/', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33274996414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33274996414.webp', 'https://www.flickr.com/photos/zaragozaantigua/33274996414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23797, 'Vista a‚îú¬Ærea 1990', 'Se aprecian las obras en la plaza del Pilar, el templete levantado frente a la Delegaci‚îú‚îÇn del Gobierno, los andamios de la restauraci‚îú‚îÇn de la Lonja, las ruinas del Foro romano en la plaza de La Seo, el Monumento a los Ca‚îú¬°dos sin terminar de desmantelar...', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65571800, -0.87649800, '0101000020E6100000124DA088450CECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885512645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885512645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885512645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23805, 'Traseras Lonja 1927', 'Imagen desde cierta altura de las traseras de La Lonja, cuando presentaban una feraz zona verde, con visual de las traseras de los edificios de la calle del Pilar, y el Pilar, al fondo. En el jard‚îú¬°n del palacio del Marqu‚îú¬Æs de Ayerbe, imagen del quiosco realizado con materiales reciclados del derribado palacio o casa de Torrellas (s. XV). Fuente: Instituto Amatller de Arte Hisp‚îú√≠nico (Arxiu Mas).', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15284977933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15284977933.webp', 'https://www.flickr.com/photos/zaragozaantigua/15284977933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23856, 'El Pilar desde la Seo 1930', 'Vista de la calle y el templo del Pilar desde la Seo, con su torre a la izquierda. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65554500, -0.87701600, '0101000020E61000001633C2DB8310ECBF350708E6E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27369756636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27369756636.webp', 'https://www.flickr.com/photos/zaragozaantigua/27369756636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23862, 'Plaza del Pilar 1966', 'Tot‚îú¬Æmica puesta en escena del acto de fe de "ver la tele", en aparatos de 20/24 pulgadas, en la plaza del Pilar, de noche, y en invierno. En el interior de la inmediata Lonja, a la derecha, estaba teniendo lugar una representaci‚îú‚îÇn de jotas, y los aparatos televisores retransmit‚îú¬°an a quienes no hab‚îú¬°an podido entrar a verlo en directo, cortes‚îú¬°a de una local empresa especializada en la venta de electrodom‚îú¬Æsticos. En la imagen, las traseras del monumento a Francisco de Goya, como tel‚îú‚îÇn de fondo al espect‚îú√≠culo, de cuando "ver la tele" era un privilegiado entretenimiento. Fuente: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65554200, -0.87691100, '0101000020E6100000C21550A8A70FECBFC493DDCCE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30074102022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30074102022.webp', 'https://www.flickr.com/photos/zaragozaantigua/30074102022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23867, 'El Pilar 1906', 'Vista del Pilar desde el paseo del Ebro, con el palacio de Ayerbe a la izquierda, y la torre sureste andamiada por estar a punto de ser terminada.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65647100, -0.87648200, '0101000020E6100000A60BB1FA230CECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30640584910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30640584910.webp', 'https://www.flickr.com/photos/zaragozaantigua/30640584910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23873, 'Procesi‚îú‚îÇn Lonja 1940', 'La Virgen del Pilar es llevada en procesi‚îú‚îÇn ante la Lonja, durante los actos del XIX centenario de su viaje a Zaragoza, exactamente el a‚îú‚ñío 40. Destaca la presencia de representantes civiles. Al fondo, la manzana de casas que en pocos a‚îú‚ñíos ser‚îú√≠ derribada para construir el nuevo ayuntamiento. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30880033041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30880033041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30880033041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23876, 'Paseo del Ebro 1940', 'Imagen capturada en los jardines y zona de esparcimiento entre la antigua Lonja y el paseo del Ebro. A la izquierda, las traseras de los edificios recayentes a la calle del Pilar, como la antigua posada de los Reyes, y el palacio de Ayerbe, con su reciclado cenador que al fondo despunta del jard‚îú¬°n vallado. Fuente visual: Ferr‚îú√≠n Forns Navarro, Ajuntament de Girona.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30979688124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30979688124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30979688124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23883, 'Palacio de Ayerbe a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste que muestra la Posada de los Reyes y el Palacio de Ayerbe, en el paseo de la Ribera. Estos edificios se encontraban entre la Lonja y el Pilar. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629399793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629399793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629399793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23902, 'Plaza del Pilar 1967', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 1 de la plaza de La Seo, esquinero con la calle de Don Jaime I. con una vista de la plaza del Pilar que alcanza hasta San Juan de los Panetes, al fondo. En primer t‚îú¬Ærmino, el moderno Monumento a Goya. La ocupaci‚îú‚îÇn de la plaza como espacio de aparcamiento de veh‚îú¬°culos progresa adecuadamente.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49328681616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49328681616.webp', 'https://www.flickr.com/photos/zaragozaantigua/49328681616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23904, 'Paseo del Ebro c.1930', 'Imagen capturada desde la altura del Seminario Conciliar en el arranque de la calle de Don Jaime I y orientada hacia el noroeste, siguiendo la perspectiva del paseo del Ebro. En primer t‚îú¬Ærmino, caseta del peso p‚îú‚ïëblico de la Puerta del ‚îú√ºngel y los Jardines de la Lonja, las traseras de los inmuebles del tramo de los impares de la calle del Pilar, con el hom‚îú‚îÇnimo templo de tel‚îú‚îÇn de fondo edilicio. A la derecha, cauce del r‚îú¬°o Ebro y arboleda de Macanaz,', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65612000, -0.87648100, '0101000020E61000008F17D2E1210CECBF32207BBDFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50150605706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50150605706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50150605706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23908, 'Paseo del Ebro c.1908', 'Despejada y luminosa imagen capturada en el paseo del Ebro a la altura del fielato de consumos de la Puerta del ‚îú√ºngel, con una interesante panor‚îú√≠mica de la antigua fachada urbana del inmediato tramo ribere‚îú‚ñío, desde la posada de los Reyes, junto a cuya solanera se concentran varios carros y caballer‚îú¬°as, las traseras y jardines de la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. A la derecha, poste del tendido el‚îú¬Æctrico de la l‚îú¬°nea de Circunvalaci‚îú‚îÇn.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65641700, -0.87668500, '0101000020E6100000AF997CB3CD0DECBFEBC4E57805D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51719140471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51719140471.webp', 'https://www.flickr.com/photos/zaragozaantigua/51719140471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23909, 'Plaza del Pilar 1966', 'Nocturna e invernal imagen capturada en la plaza del Pilar y en el entorno al monumento a Francisco de Goya, centrada en el montaje realizado por el establecimiento "Radio La Corona" consistente en la instalaci‚îú‚îÇn de algo m‚îú√≠s de treinta televisores "Vanguard" para ofrecer la retransmisi‚îú‚îÇn de la ceremonia de homenaje al equipo cultural-deportivo que presidido por el fot‚îú‚îÇgrafo Guillermo Fat‚îú√≠s Ojuel representaba a Zaragoza en el concurso de TVE "La uni‚îú‚îÇn hace la fuerza" y en el que result‚îú‚îÇ ganador. Tambi‚îú¬Æn fueron homenajeados los componentes del equipo finalista, de La Coru‚îú‚ñía. Adem‚îú√≠s los ganadores se llevaron 999.999 pesetas, y 333.333 los finalistas. Mientras en la Lonja ten‚îú¬°a lugar la gran ceremonia de homenaje con presencia de las autoridades locales y del jefe de programas de TVE, se‚îú‚ñíor Adolfo Su‚îú√≠rez Gonz‚îú√≠lez, siendo presentada y animada por los conductores del programa televisivo se‚îú‚ñíores Mario Beut y Antol‚îú¬°n Garc‚îú¬°a, estos televisores sirvieron al doble prop‚îú‚îÇsito de ofrecer las im‚îú√≠genes retransmitidas en directo a quienes no pudieron ingresar al interior de la Lonja, y de servir de publicidad para la firma comercial que los instal‚îú‚îÇ. Al fondo y a la izquierda del abarrotado entorno al monumento a Goya, cartel luminoso del Cine Pax en la plaza de La Seo.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52464858820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52464858820.webp', 'https://www.flickr.com/photos/zaragozaantigua/52464858820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23965, 'Requet‚îú¬Æ navarro 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. Tras el 18 de julio, voluntarios carlistas navarros, o requet‚îú¬Æs (denominaci‚îú‚îÇn de los soldados carlistas durante la Primera Guerra Carlista, 1833-1840), secundaron las fuerzas nacionalistas que se levantaron en armas contra la Rep‚îú‚ïëblica democr‚îú√≠tica. "Pacificada" Navarra, se plantaron como fuerza de choque armada en los frentes abiertos, como Zaragoza. En la imagen, el √î√á¬£Tercio de Do‚îú‚ñía Mar‚îú¬°a de las Nieves√î√á√ò de requet‚îú¬Æs navarros, tras cruzar el puente de Piedra, llega al entorno de la Seo. A la izquierda, la Lonja y la calle del Pilar. Al fondo, el cuartel de San L‚îú√≠zaro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65571100, -0.87630900, '0101000020E61000004818062CB90AECBF50508A56EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020622255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020622255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020622255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23971, 'Majas Internacionales 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/05/1975. "Majas Internacionales." En coherencia con la declaraci‚îú‚îÇn por parte de la ONU de 1975 como "A‚îú‚ñío Internacional de la Mujer", en Zaragoza se celebra la org‚îú√≠nica elecci‚îú‚îÇn de la "Maja Internacional". En la imagen, las aspirantes al t‚îú¬°tulo, tras una recepci‚îú‚îÇn oficial en el Ayuntamiento a cargo del Alcalde, Mariano Horno Liria, hacen un simp‚îú√≠tico posado-homenaje ante el monumento a Francisco Goya en la Plaza del Pilar, pero Goya no cabe en la foto. Al fondo, a la izquierda, cartel del Cine Pax. A la derecha, encima de la Estatua de la Libertad humanizada, visual de la plaza de La Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65548700, -0.87679200, '0101000020E6100000309FAC18AE0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15111823609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15111823609.webp', 'https://www.flickr.com/photos/zaragozaantigua/15111823609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23979, 'Mu‚îú‚ñíecos timbaleros 1905', 'Fotograbado "La Luz". 1905. "Los timbaleros del Ayuntamiento". Esta tarjeta postal reproduce el fotomontaje de unos mu‚îú‚ñíecos vestidos con el uniforme de Timbaleros del Ayuntamiento, delante de una imagen de la fachada del entonces edificio del Ayuntamiento de la ciudad, situado en las traseras de La Lonja. A‚îú‚ñíos despu‚îú¬Æs el Ayuntamiento ser‚îú¬°a trasladado a la calle de la Democracia. Fuente: "La tarjeta postal ilustrada", Francisco Pal‚îú√≠ Laguna.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15299563115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15299563115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15299563115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23980, 'Pablo Serrano 1975', 'Pablo Serrano Aguilar durante el montaje de la Exposici‚îú‚îÇn antol‚îú‚îÇgica organizada por la Comisi‚îú‚îÇn de Cultura del Ayuntamiento en el Palacio de la Lonja (marzo-abril de 1975), con el posado del autor junto a Interpretaci‚îú‚îÇn de La Piedad, una de las obras expuestas. En septiembre de ese a‚îú‚ñío, y en protesta por los fusilamientos ejecutados por el r‚îú¬Ægimen franquista a finales de ese mes, retir‚îú‚îÇ su obra de la exposici‚îú‚îÇn Telecom 75 (Ginebra, Suiza).', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65584700, -0.87662100, '0101000020E6100000FF93BF7B470DECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15302777212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15302777212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15302777212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24071, 'La Lonja 1966', 'Imagen de la danesa Jeannette Christjansen (centro) tras su proclamaci‚îú‚îÇn como Maja Internacional 1966 en la Lonja, acompa‚îú‚ñíada de sus cuatro Damas de Honor: de izquierda a derecha, la irlandesa Muriel O''Hanlon, la belga Rossette Menegain, la francesa Liliane Burnier, y la espa‚îú‚ñíola Silvia Veiga. En el posado van vestidas a la manera tradicionalista de maja espa‚îú‚ñíola, y Jeannette luce capote de brega firmado para la ocasi‚îú‚îÇn por el popular matador de toros Manuel Ben‚îú¬°tez "El Cordob‚îú¬Æs". El jurado del certamen estuvo compuesto por ilustres damas locales, esposas de las autoridades provinciales, y varios "cr‚îú¬°ticos de bellezas femeninas" como el modisto Pedro Rodr‚îú¬°guez, el director del No-Do, Manuel Augusto Garc‚îú¬°a Vi‚îú‚ñíolas (se rod‚îú‚îÇ un reportaje para este noticiario), Pedro Chicote, y Antonio Mingote. Fuente visual: revista Blanco y Negro (Madrid), en hemeroteca.abc.es/', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34333147690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34333147690.webp', 'https://www.flickr.com/photos/zaragozaantigua/34333147690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24081, 'Calle Don Jaime 1904', 'Foto: Lete. En el marco de las fiestas de octubre, se celebr‚îú‚îÇ una recepci‚îú‚îÇn municipal a "los representantes de la Coronilla de Arag‚îú‚îÇn". La imagen capta el momento en que estos llegan "con su famosa senyera" hasta las casas del Ayuntamiento, al fondo. A la izquierda, fachada este de la Lonja. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65574000, -0.87634200, '0101000020E6100000368FC360FE0AECBFEB56CF49EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39256330224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39256330224.webp', 'https://www.flickr.com/photos/zaragozaantigua/39256330224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21354, 'Plaza de la Constituci‚îú‚îÇn 1900', 'Invernal escena capturada en la plaza de la Constituci‚îú‚îÇn centrada en el emboque a la calle de los M‚îú√≠rtires, flanqueada por los inmuebles de los n‚îú‚ïëmeros 35-39 del Coso a la izquierda y los n‚îú‚ïëmeros 41-45 a la derecha. En la solana de los bajos de estos edificios destaca la nutrida presencia de varias decenas de paisanos en lo que era denominado castiza y clasistamente "brasero de los pobres", uno de los varios existentes en la ciudad. A la derecha y en la calzada inmediata puede verse un coche cerrado tipo C, posiblemente de los construidos en Liverpool por Julius G. Neville, en servicio en la l‚îú¬°nea de Torrero. Si bien el Ayuntamiento hab‚îú¬°a autorizado en 1898 el cambio de sistema de tracci‚îú‚îÇn para seguir as‚îú¬° el modelo de la pionera Bilbao, en la imagen este coche sigue estando traccionado por una pareja de machos que le daban una velocidad media de 10-15 km/hora. En primer t‚îú¬Ærmino, la Fuente de la Princesa, sobre la que ya desde 1886 pend‚îú¬°a la amenaza de desmonte y sustituci‚îú‚îÇn primero por otra fuente "m‚îú√≠s c‚îú‚îÇmoda y m‚îú√≠s art‚îú¬°stica", una estatua del Justicia Juan Lanuza luego, y finalmente el monumento que hoy ocupa su lugar. Por ello, no eran extra‚îú‚ñíos los abundantes y denigrantes ep‚îú¬°tetos difundidos en la prensa de la ‚îú¬Æpoca y dedicados a ella como cada vez que en esta ciudad se quiere derribar o desmontar alg‚îú‚ïën edificio o monumento: "antigua", "antiest‚îú¬Ætica", "horrible", "vetusta"... En la imagen puede apreciarse que le falta el brazo derecho, efecto derivado de la agresi‚îú‚îÇn de un paisano pasado de algo. Parece ser magn‚îú¬Ætica la presencia de este bulto redondo, se encuentre ubicado donde sea, a las agresiones en su contra, bien centradas en su extendido brazo derecho o bien en el tridente que porta. Ya en 1860 se le tuvo que reponer este mismo brazo con motivo de la visita de la reina Isabel II que tuvo lugar ese a‚îú‚ñío.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65220100, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54776029575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54776029575.webp', 'https://www.flickr.com/photos/zaragozaantigua/54776029575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24124, 'La Lonja 1966', 'Imagen capturada en la Lonja durante la "presentaci‚îú‚îÇn en sociedad" de treinta y cinco "damitas zaragozanas" pertenecientes a la alta sociedad local en la "Gran Gala de Debutantes" organizada por la Comisi‚îú‚îÇn de Fiestas el 8 de octubre de ese a‚îú‚ñío. La fiesta escenific‚îú‚îÇ que estas j‚îú‚îÇvenes de la Zaragoza de bien vest‚îú¬°an "sus primeras galas de mujer" por primera vez en un festejo colectivo que tradicionalmente se realizaba de forma individual, bien en el Casino Mercantil, bien en la propia Lonja municipal. El inusual n‚îú‚ïëmero de "jovencitas" participantes en 1966 fue sustancialmente reducido en a‚îú‚ñíos siguientes, probablemente para conferir al acto un car‚îú√≠cter m‚îú√≠s exclusivo y menos colectivo, o tal vez por el creciente desapego social a este tipo de ceremoniales tan carpetovet‚îú‚îÇnicos. En la imagen posan escalonadas las treinta y cinco "bell‚îú¬°simas se‚îú‚ñíoritas debutantes en primorosos modelos de noche" portando una rosa roja. Las flanquean elementos de la Polic‚îú¬°a Municipal en traje de gala. A la izquierda y ante el micr‚îú‚îÇfono, Demetrio Gal‚îú√≠n Bergua pronuncia un discurso "dedicado a exaltar las virtudes y belleza de nuestras mujeres" y donde les advert‚îú¬°a que "de ahora en adelante deb‚îú¬°an ser modelos y prototipos de damas aragonesas", sea lo que sea que significara esta aserci‚îú‚îÇn.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54664598920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54664598920.webp', 'https://www.flickr.com/photos/zaragozaantigua/54664598920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24125, 'La Lonja 1967', 'Imagen capturada en la Lonja durante la exclusiva e inici‚îú√≠tica "gran gala de debutantes" que tuvo lugar el 7 de octubre de ese a‚îú‚ñío organizada por el Ayuntamiento en beneficio de la Asociaci‚îú‚îÇn Nacional de la Lucha Contra el C‚îú√≠ncer. La habitual presencia de las primeras autoridades locales fue eclipsada por acudir a ella para presidir el acto en carne mortal la unig‚îú¬Ænita Mar‚îú¬°a del Carmen Franco Mart‚îú¬°nez-Bordi‚îú‚ïë, consorte X marquesa de Villaverde, en su calidad de presidenta de la referida asociaci‚îú‚îÇn anticancer‚îú¬°gena, acompa‚îú‚ñíada por su esposo el docto marqu‚îú¬Æs, al que las malas lenguas calificaban por razones que no vienen al cuento como "El Yern‚îú¬°simo", "marqu‚îú¬Æs de Vespaverde" o "marqu‚îú¬Æs de Vayavida". En esta ocasi‚îú‚îÇn fueron quince las "se‚îú‚ñíoritas debutantes vestidas de blanco y magn‚îú¬°ficas en su juventud y belleza" que "vistieron sus primeras galas de mujer". En la imagen algunas de ellas posan ordenadas en filas tras saludar personalmente y recibir de manos de la marquesa de Villaverde sus "carnets de baile" y antes de su desfile tras el que se sentar‚îú¬°an para dar inicio a la cena y el posterior baile que dur‚îú‚îÇ hasta las primeras horas de la madrugada, amenizado por las orquestas "Los Magos y Farr‚îú¬Æs" y el conjunto "Los Sarakostas" y que cont‚îú‚îÇ adem‚îú√≠s con las actuaciones de Mar‚îú¬°a Dolores Pradera, acompa‚îú‚ñíada de los Gemelos; el d‚îú‚ïëo Juan y Junior, y el Quinteto del Club de Jazz de Radio Zaragoza.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54668742814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54668742814.webp', 'https://www.flickr.com/photos/zaragozaantigua/54668742814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24138, 'Feria de Muestras 1934', 'Foto A. de la Barrera, 1934. Interior de la Lonja de Zaragoza durante la celebraci‚îú‚îÇn de la I Feria de Muestras Regional Aragonesa. Vemos la esquina suroeste del edificio, con el stand de la Sociedad General de Esterilizaci‚îú‚îÇn, cuyo domicilio social estaba en la calle de Joaqu‚îú¬°n Costa 16. El procedimiento dom‚îú¬Æstico Foncal, patentado por esa empresa, consegu‚îú¬°a matar las bacterias del agua mediante un proceso catal‚îú¬°tico, al instalar en las tuber‚îú¬°as un ingenio met‚îú√≠lico. Fuente: Revista Arag‚îú‚îÇn, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65585400, -0.87681500, '0101000020E61000003B8DB454DE0EECBFB3791C06F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20031364553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20031364553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20031364553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24143, 'Feria de Muestras 1934', 'Plano del recinto de la I Feria de Muestras Regional Aragonesa, 1934. La Sociedad Econ‚îú‚îÇmica Aragonesa de Amigos del Pa‚îú¬°s organiz‚îú‚îÇ en 1934 la primera Feria de Muestras Aragonesa en el palacio de la Lonja y sus jardines adyacentes. Se trataba de un muestrario de empresas de industria y comercio, que aparecen en el listado bajo el gr‚îú√≠fico. La entrada ten‚îú¬°a lugar en el edificio, por la calle Don Jaime I, y la salida por los jardines. Al a‚îú‚ñío siguiente se celebr‚îú‚îÇ la segunda, en la ‚îú‚ïëltima zona de cubrimiento del r‚îú¬°o Huerva, cercana a la plaza de Para‚îú¬°so. No hubo m‚îú√≠s, hasta 1941. Fuente: Revista Arag‚îú‚îÇn, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65592600, -0.87654600, '0101000020E610000056116E32AA0CECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20465197289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20465197289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20465197289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24154, 'Expo 1919', 'Medalla en bronce realizada por el escultor Jos‚îú¬Æ Clara para conmemorar la Exposici‚îú‚îÇn Hispano-Francesa de Bellas Artes celebrada en la Lonja durante los meses de mayo y junio de ese a‚îú‚ñío, en cuya secci‚îú‚îÇn espa‚îú‚ñíola se pudo ver obras de, entre otros, Nonell, Picasso, Regoyos, Zuloaga, Benlliure, Gargallo, Julio Antonio, y Macho. De la parte francesa, la representaci‚îú‚îÇn incluy‚îú‚îÇ, entre otros, a los pintores Vlaminck, Friesz, Camoin, siendo la primera vez que en Zaragoza se ve‚îú¬°an sus obras "fauves". Esta exposici‚îú‚îÇn, a diferencia de la de 1908, apenas fue cubierta por los medios de comunicaci‚îú‚îÇn, de forma que casi nadie se enter‚îú‚îÇ, ni antes, durante, ni despu‚îú¬Æs. La medalla de la imagen representa idealmente a Francia, con Marianne, y a Espa‚îú‚ñía, con una baturra, tal vez de nombre Pilar. Fuente visual: www.museunacional.cat/', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30144516644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30144516644.webp', 'https://www.flickr.com/photos/zaragozaantigua/30144516644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22315, 'Calle de Pedro Cubero c.1965', 'Procesi‚îú‚îÇn de Santa Rosa de Lima, patrona del barrio de Las Fuentes, a cargo de los tranviarios residentes en el Grupo Vizconde de Escoriaza, pasando por la calle de Pedro Cubero en direcci‚îú‚îÇn a la de Salvador Minguij‚îú‚îÇn, procedente la parroquia del mencionado Grupo de viviendas, levantado en 1953 para los trabajadores de la sociedad Tranv‚îú¬°as de Zaragoza. Su presidente, ‚îú√ºngel Escoriaza Castill‚îú‚îÇn, introdujo el culto a la santa peruana en el barrio.', 1965, 1965, 1965, 'Anos 60', 'LAS FUENTES', 41.64783000, -0.86011000, '0101000020E61000004BCD1E680586EBBF10AFEB17ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15759816212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15759816212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15759816212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24155, 'La Lonja 1919', 'Imagen del interior de la antigua Lonja, como escenario de la Exposici‚îú‚îÇn Hispano-Francesa de Bellas Artes celebrada durante los meses de mayo y junio de ese a‚îú‚ñío. La toma longitudinal (posiblemente con el lienzo este al fondo), ilustra la disposici‚îú‚îÇn espacial de algunos de los bultos redondos y cuadros de la exposici‚îú‚îÇn, la decoraci‚îú‚îÇn con motivos florales, y la iluminaci‚îú‚îÇn por medio de grandes l‚îú√≠mparas que penden de las renacentistas b‚îú‚îÇvedas. De entre los bultos redondos que aparecen en la imagen, destacamos las dos obras de Jos‚îú¬Æ Clar‚îú√≠: "El crep‚îú‚ïësculo", y "La diosa". Del local escultor Jos‚îú¬Æ Bueno, que entonces estaba terminando su recreaci‚îú‚îÇn del rey Alfonso I "El Batallador" para el monumento del cabezo de Buenavista, esta muestra cont‚îú‚îÇ con sus obras "La tarde", y "Humanidad". La primera decorar‚îú¬°a un jard‚îú¬°n urbano cerca de la plaza de Arag‚îú‚îÇn, y la segunda ser‚îú¬°a colocada en la "fosa com‚îú‚ïën" del cementerio. Fuente visual: Foto Cepero, revista "La Esfera", en hemerotecadigital.bne.es/', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30752746936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30752746936.webp', 'https://www.flickr.com/photos/zaragozaantigua/30752746936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24163, 'Feria de Muestras 1934', 'Imagen con uno de los carteles anunciadores de la primera Feria de Muestras organizada en octubre de 1934 en el recinto de la Lonja y sus adyacentes jardines, en una instalaci‚îú‚îÇn coordinada por el arquitecto Borobio. El cartel, dise‚îú‚ñíado por Guillermo P‚îú¬Ærez, recoge precisamente la antigua Lonja como escenario central de la muestra, y se centra en su fachada recayente a la calle de Don Jaime I. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36522148345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36522148345.webp', 'https://www.flickr.com/photos/zaragozaantigua/36522148345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24165, 'Paseo del Ebro 1934', 'Excepcional imagen capturada en el paseo del Ebro y centrada en el cruce con la calle de Don Jaime I, donde destaca el montaje realizado con motivo de la I Feria de Muestras Regional Aragonesa, celebrada entre el 5 y el 20 de octubre de 1934 en el espacio de la antigua Lonja, con 51 "stands", y los jardines inmediatos, donde se dio cabida a otros 27 "stands" adem‚îú√≠s de un bar y un tablado para m‚îú‚ïësica. Junto a la zona de los pabellones montados donde estuviera la antigua Casa Consistorial, delimitados por numerosas banderas y banderolas festivas, la caseta de consumos de la Puerta del ‚îú√ºngel y el quiosco de la Sociedad Protectora de Animales. De fondo, la monumental fachada al paseo formada por las traseras de la calle del Pilar, con la Posada del Rey y el palacio de los marqueses de Ayerbe, y el templo del Pilar. Por el paseo circula un tranv‚îú¬°a de la l‚îú¬°nea "6. Magdalena-Mercado". En primer t‚îú¬Ærmino y a la izquierda, esquina del Seminario conciliar. Hacia la derecha, acceso al Puente de Piedra.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65605600, -0.87621300, '0101000020E6100000C18F6AD8EF09ECBF1B2C9CA4F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52278034883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52278034883.webp', 'https://www.flickr.com/photos/zaragozaantigua/52278034883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24219, 'Comparsa 1901', 'Gigantes y Cabezudos junto a la Lonja en 1901. La comparsa est‚îú√≠ viniendo por la calle del Pilar (a la izquierda) hacia la de Don Jaime I. La imagen est‚îú√≠ tomada desde la plaza de La Seo. En primer t‚îú¬Ærmino, el cabezudo Robaculeros.', 1901, 1901, 1901, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65546700, -0.87647600, '0101000020E61000001E537765170CECBFBA4DB857E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246931012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246931012.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246931012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24226, 'Timbaleros 1891', '"Los timbaleros de la ciudad de Zaragoza", ‚îú‚îÇleo sobre lienzo, Anselmo Gasc‚îú‚îÇn de Gotor, 1891. Los timbaleros, al frente de una comitiva de ministriles seguida de los maceros. Tras ellos, los oficios concejiles con sombreros de copa. Salen del Ayuntamiento, a la derecha de la Lonja y fuera de la imagen. Al fondo, la calle del Pilar. Fuente: "El municipio en Arag‚îú‚îÇn", DPZ, 2004.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65553200, -0.87653900, '0101000020E6100000B66455849B0CECBFA1BDFA78E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20532962772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20532962772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20532962772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24233, 'Gigantes y cabezudos 1859', 'Dibujo alusivo a las fiestas del Pilar de 1859, con la comparsa de gigantes y cabezudos, proveniente de la calle del Pilar y situada en la plaza de La Seo, con vistas a la Lonja (al fondo a la derecha). Estas figuras ser‚îú√≠n remplazadas al a‚îú‚ñío siguiente por las dise‚îú‚ñíadas por F‚îú¬Ælix Oroz. Tambi‚îú¬Æn el edificio de la izquierda desaparecer‚îú√≠ en poco tiempo.', 1859, 1859, 1859, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29398419343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29398419343.webp', 'https://www.flickr.com/photos/zaragozaantigua/29398419343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24385, 'Calle del Pilar 1931', 'En el contexto de la celebraci‚îú‚îÇn del Centenario IV del nacimiento de Teresa de Cepeda y Ahumada, la Compa‚îú‚ñí‚îú¬°a de Santa Teresa de Jes‚îú‚ïës proyecta en 1915 una expansi‚îú‚îÇn que incluye la estrat‚îú¬Ægica plaza de Zaragoza, con la idea de fundar una escuela de formaci‚îú‚îÇn de maestras cat‚îú‚îÇlicas. En setiembre de ese a‚îú‚ñío llegan a la ciudad las primeras HH. Teresianas a buscar ubicaci‚îú‚îÇn, mientras se alojan donde las Oblatas (P‚î¨‚ïë de las Damas). El Arzobispo Soldevila les ofrece las ruinas del antiguo convento de las Adoratrices, en San Juan de los Panetes, mas se inclinan por un piso de alquiler en la calle del Pilar, con el azulejo n‚îú‚ïëmero 19, en el edificio esquinero justo antes de la Seo, donde confluye la calle de Bayeu. Establecidas ya al comienzo de ese curso, el piso qued‚îú‚îÇ pronto peque‚îú‚ñío, debiendo expandirse al entresuelo y a dos pisos extra del mismo edificio para dar cabida tanto a las alumnas internas de magisterio, como al alumnado externo de primeras ense‚îú‚ñíanzas. La demanda de plazas continuaba, y resultaba imposible continuar all‚îú¬°, de forma que a comienzos de los a‚îú‚ñíos 20 se busc‚îú‚îÇ una nueva ubicaci‚îú‚îÇn, m‚îú√≠s espaciosa, que se encontr‚îú‚îÇ en los promisorios terrenos en urbanizaci‚îú‚îÇn de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. La imagen de Roisin est‚îú√≠ realizada desde la plaza de la Seo, cuando el Colegio Teresiano estaba ya en su nueva ubicaci‚îú‚îÇn de la calle Sanclemente, aunque la fenomenal fotograf‚îú¬°a recoge tal vez la mejor instant‚îú√≠nea con detalle del edificio de la calle del Pilar (donde la panader‚îú¬°a) que acogi‚îú‚îÇ la primera sede zaragozana del Colegio Teresiano del Pilar. Como todos sus vecinos de zona, a excepci‚îú‚îÇn de la Lonja, este edificio ser‚îú¬°a demolido a finales de d‚îú¬Æcada. Fuente visual: Lucien Roisin, "Lonja y torres del Pilar", en "Zaragoza, a‚îú‚ñíos veinte. 81 fotograf‚îú¬°as de Roisin (1925-1931)", Instituci‚îú‚îÇn Fernando el Cat‚îú‚îÇlico, 2014. Fuente textual: Exposici‚îú‚îÇn "Centenario Compa‚îú‚ñí‚îú¬°a Santa Teresa de Jes‚îú‚ïës - Zaragoza", y la muy amable colaboraci', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65574200, -0.87692200, '0101000020E6100000BC92E4B9BE0FECBF8B4E965AEFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23134325411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23134325411.webp', 'https://www.flickr.com/photos/zaragozaantigua/23134325411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24586, 'Lonja con andamio 1889', 'J. L‚îú¬Ævy et Cie. "Palais de la bourse" (Palacio de la Bolsa), 1889 Podemos ver la Lonja con andamiaje, un tranv‚îú¬°a "de sangre" y un heterog‚îú¬Æneo conjunto de viandantes por el final de la calle de Don Jaime.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65550300, -0.87646400, '0101000020E61000000DE2033BFE0BECBF07B7B585E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794547078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794547078.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794547078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24587, 'Lonja de Mercaderes. Interior. 1885', 'A.M.Z. Sign. 0913. La Lonja, Zaragoza. [1885] Magn‚îú¬°fico edificio civil renacentista que albergaba las reuniones de los pr‚îú‚îÇceres mercantiles de la ciudad (1551). Hoy sigue en pie en la plaza del Pilar, mostrando exposiciones municipales.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65577200, -0.87651500, '0101000020E610000095826E2F690CECBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858893205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858893205.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858893205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24590, 'Lonja c.1877', 'Jean Laurent, "Zaragoza-La Lonja". Al principio de la antigua calle de la Cuchiller‚îú¬°a, otra de las im‚îú√≠genes de la Lonja capturadas por Jean Laurent, en tiempos en que era utilizada como espacio para actos p‚îú‚ïëblicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no pod‚îú¬°an pagarse el no hacerlo), y algunas representaciones teatrales. A su derecha, y pegado, el edificio de la Casa Consistorial levantado unas d‚îú¬Æcadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden d‚îú‚îÇrico. Fuente: "Mirar el mundo otra vez. 25 a‚îú‚ñíos de fotograf‚îú¬°a en la galer‚îú¬°a Spectrum".', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16610030380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16610030380.webp', 'https://www.flickr.com/photos/zaragozaantigua/16610030380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24593, 'Puerta del ‚îú√ºngel c.1865', 'Vista de la ‚îú‚ïëltima versi‚îú‚îÇn de la Puerta del ‚îú√ºngel, con la Lonja en primer plano a la izquierda, seguida de las casas consistoriales. Fuente: Instant‚îú√≠neas zaragozanas, CAMPZAR, 1982.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24865007091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24865007091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24865007091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24595, 'La Lonja 1991', 'Imagen de la escultura en bronce titulada "Caballito", con posado de su autor, el modelista Francisco Rallo Lahoz, en las traseras de la Lonja. El bronc‚îú¬°neo equino fue concebido como homenaje de la ciudad al fot‚îú‚îÇgrafo Angel Cordero Gracia, que ejerci‚îú‚îÇ de "minutero" en los jardines de la plaza de la Lonja recayentes al paseo del Ebro, entre 1925 y 1978, en el entorno donde fue ubicado este bulto redondo. El original caballito era de cart‚îú‚îÇn piedra, y en ‚îú¬Æl se sentaban las ni‚îú‚ñías y ni‚îú‚ñíos que iban a ser retratados. Posiblemente esta imagen fuera capturada en la inauguraci‚îú‚îÇn oficial de esta obra. Fuente visual: Antonio Calvo Pedr‚îú‚îÇs, AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30491155170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30491155170.webp', 'https://www.flickr.com/photos/zaragozaantigua/30491155170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24596, 'La Lonja c.1902', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n‚î¨‚ïë 134 de las im‚îú√≠genes de "Zaragoza" incluidas en la serie postal de Espa‚îú‚ñía para la Uni‚îú‚îÇn Postal Universal, que captura una vista canicular de la Lonja desde cierta altura, en la arbolada plaza de la Seo. A la izquierda, la ensanchada esquina del final de la calle del Pilar. A la derecha, en la calle de Don Fernando el Cat‚îú‚îÇlico, la Casa del Ayuntamiento. Al fondo, el puente de Piedra y casas del Arrabal. Fuente visual: www.todocoleccion.net/', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33908400994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33908400994.webp', 'https://www.flickr.com/photos/zaragozaantigua/33908400994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24598, 'La Lonja c.1892', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n‚î¨‚ïë 287 entre las im‚îú√≠genes de "Zaragoza" incluidas en la serie postal de Espa‚îú‚ñía, que captura una vista de la Lonja desde la zona de sombra ma‚îú‚ñíanera de la plaza de la Seo. A la izquierda, la esquina del final de la calle del Pilar. A la derecha, las Casas de la Ciudad, o ayuntamiento. En la plaza, a la derecha, e inmediatas, un grupo de mujeres se abastecen de agua en la fuente de la Samaritana (fuera de plano). Fuente visual: www.todocoleccion.net/', 1892, 1892, 1892, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34673697456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34673697456.webp', 'https://www.flickr.com/photos/zaragozaantigua/34673697456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24599, 'La Lonja 1844', '"Sal‚îú‚îÇn de la Lonja", como parte integrante de las Casas de la Ciudad, o Ayuntamiento. Fuente visual: "Recuerdos y Bellezas de Espa‚îú‚ñía. Obra destinada a dar a conocer sus monumentos, antig‚îú‚ïùedades y vistas pintorescas en l‚îú√≠minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa‚îú‚ñíadas de texto por P. Piferrer y J. M. Quadrado. Arag‚îú‚îÇn: Jos‚îú¬Æ Mar‚îú¬°a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34737152251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34737152251.webp', 'https://www.flickr.com/photos/zaragozaantigua/34737152251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24600, 'Marqu‚îú¬Æs de Almenara 1591', '"El pueblo zaragozano hiere al marqu‚îú¬Æs de Almenara". Ilustraci‚îú‚îÇn de F. Blanch que recrea el ataque de algunos ciudadanos en 1591 contra ‚îú√¨‚îú‚ñíigo Hurtado de Mendoza y de la Cerda, marqu‚îú¬Æs de Almenara, enviado por Felipe II a Zaragoza en 1588. Muri‚îú‚îÇ en la c‚îú√≠rcel dos semanas despu‚îú¬Æs. Al fondo, la calle del Pilar, la Lonja y las casas consistoriales. A la derecha, fragmento de la Diputaci‚îú‚îÇn del Reino en la plaza de la Seo. Fuente visual: Historia de Espa‚îú‚ñía, Miguel Segu‚îú¬°, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65548300, -0.87641700, '0101000020E6100000E01115AA9B0BECBFBF0AF0DDE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40204809215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40204809215.webp', 'https://www.flickr.com/photos/zaragozaantigua/40204809215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24601, 'Plaza del Pilar 1981', 'Imagen capturada en la plaza del Pilar junto al ingreso principal a la Lonja, escenario de la Exposici‚îú‚îÇn "50 aniversario del Cuerpo de Bomberos de Zaragoza", donde se conmemoraba a constituci‚îú‚îÇn de este Cuerpo como servicio profesional de extinci‚îú‚îÇn de incendios a cargo del Ayuntamiento en el a‚îú‚ñío 1931. El veh‚îú¬°culo de primer t‚îú¬Ærmino formaba parte de la exposici‚îú‚îÇn de material hist‚îú‚îÇrico de bomberos, y se trata de un cami‚îú‚îÇn que transportaba una escalera m‚îú‚îÇvil Magirus E-1 que estuvo en servicio desde 1937 y hasta 1966. Se considera que el ‚îú¬Æxito de esta exposici‚îú‚îÇn fue el germen del Museo del Fuego inaugurado en 2012.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50143937168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50143937168.webp', 'https://www.flickr.com/photos/zaragozaantigua/50143937168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24605, 'Plaza de la Seo 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Marzo 1974. Imagen de la Plaza de la Seo desde la calle Don Jaime. La fuente que aparece fue la que sustituy‚îú‚îÇ a la de La Samaritana, cuando fue desmontada y trasladada, primero al Parque Bruil, luego a la Plaza del Justicia. M‚îú√≠s tardes, a finales de los a‚îú‚ñíos 80, la Plaza de la Seo hab‚îú¬°a alcanzado un lamentable estado que llev‚îú‚îÇ a redactar un proyecto de remodelaci‚îú‚îÇn que inclu‚îú¬°a el regreso de La Samaritana, pero el hallazgo de los restos del Foro Romano obligaron a transformar el proyecto en lo que hoy vemos.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65551100, -0.87642200, '0101000020E610000052D66F26A60BECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14718879029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14718879029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14718879029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24608, 'La Seo a‚îú‚ñíos 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. [Plaza del Pilar] La Torre de la Seo [o La Catedral del Salvador en su Epifan‚îú¬°a y Puerta de San Bartolom‚îú¬Æ en la fachada principal o neoc‚îú√≠sica]". Imagen tomada desde la calle el Pilar. Fuente visual: Archivo W‚îú‚ïùnderlich (WUN-05810) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65570300, -0.87679200, '0101000020E6100000309FAC18AE0EECBFCE716E13EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877342207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877342207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877342207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24612, '‚îú√ºngel Cordero Gracia 1974', '‚îú√ºngel Cordero Gracia ejerci‚îú‚îÇ de fot‚îú‚îÇgrafo minutero desde 1925, retratando ni‚îú‚ñíos y ni‚îú‚ñías sobre un caballito de madera en los jardines traseros de la Lonja. Era Minutero porque entre el posado, la instant‚îú√≠nea, y el revelado, se suced‚îú¬°an escasos minutos, una pr‚îú√≠ctica que estuvo realizando hasta 1978, y por la que pasaron varias generaciones de j‚îú‚îÇvenes, y no tan j‚îú‚îÇvenes, bien locales, o de paso por la ciudad. En 1991 el Ayuntamiento homenaje‚îú‚îÇ su memoria instalando, en el mismo espacio donde estuvo trabajando tanto tiempo, una escultura en bronce sobre pedestal circular de granito rosa, obra de Francisco Rallo Lahoz, que representa al caballito protagonista de tantas instant‚îú√≠neas. En la imagen, ‚îú√ºngel Cordero se encamina, cargado con sus herramientas de trabajo recogidas en la plaza de San Bruno n‚î¨‚ïë 3, hacia la Lonja cruzando por la plaza de La Seo. El objetivo de la c‚îú√≠mara, aun cubierto, nos observa√î√á¬™', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65551100, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15047796462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15047796462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15047796462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24627, 'Calle del Pilar 1920', 'Foto: Julio Requejo. Aspecto de la calle del Pilar con la Seo al fondo, en junio de 1920. La imagen ha sido volteada horizontalmente para su correcta visualizaci‚îú‚îÇn. Fuente: DARA/AHPZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21193339789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21193339789.webp', 'https://www.flickr.com/photos/zaragozaantigua/21193339789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24658, 'Plaza de La Seo c.1942', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 19 de la antigua calle del Pilar antes de su derribo para despejar de viejas casonas el tramo m‚îú√≠s oriental de la ampliada plaza del Pilar, y dejar espacio a la nueva Casa Consistorial. Inmediata y a la izquierda, la Lonja, y al fondo, la plaza de La Seo. A la derecha y fuera de plano, el despejado solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65578300, -0.87694200, '0101000020E610000083A44FABE80FECBFEA2285B2F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49305726783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49305726783.webp', 'https://www.flickr.com/photos/zaragozaantigua/49305726783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25198, 'Puerta del ‚îú√ºngel 1851', '"Dibujos que representan dos proyectos para la Puerta del ‚îú√ºngel de esta Ciudad, arreglados ‚îú√≠ lo mandado por M. II. SS. Gobernador de la Provincia, y Alcalde Corregidor de esta Capital". Zaragoza, 12 de septiembre de 1851. Ninguno de los dos proyectos de esta puerta, entre las Casas Consistoriales y el Seminario Conciliar, fue levantado. En 1860 se erigi‚îú‚îÇ otro modelo, obra de Miguel Jeliner y Germ‚îú√≠. Fuente: AMZ.', 1851, 1851, 1851, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126168596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126168596.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126168596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25650, 'Don Jaime I c.1925', 'Archivo Municipal de Zaragoza. "Procesi‚îú‚îÇn religiosa" en la que, aunque as‚îú¬° lo parezca, quien va solemne bajo palio no es el tranv‚îú¬°a de la L‚îú¬°nea "Arrabal". Imagen tomada en la calle Don Jaime, con la Lonja a la izquierda, y la plaza de la Seo a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65562200, -0.87640700, '0101000020E6100000FD885FB1860BECBFE144F46BEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964558620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964558620.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964558620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25671, 'Don Jaime I, c.1925', '"Zaragoza II. [La Lonja]". Captura visual del entronque de la calle de don Jaime I, la calle del Pilar, a la izquierda, y la arbolada plaza de la Seo, a la derecha. Al fondo, el puente de Piedra. Vertebra la imagen el sencillo e imponente edificio de la antigua Lonja de mercaderes, ya despejada de las derribadas Casas de la Ciudad. A la izquierda, el antiguo n‚î¨‚ïë 6 de la calle Don Jaime I, derribado durante la radical creaci‚îú‚îÇn de la gran plaza del Pilar. Incrustados en el firme, los ra‚îú¬°les tranviarios de las ya electrificadas l‚îú¬°neas "Arrabal" y "G‚îú√≠llego". La circulaci‚îú‚îÇn rodada, fluida. Fuente visual: Archivo del Conde de Polentinos (Aurelio de Colmenares y Orgaz), Fototeca del Patrimonio Art‚îú¬°stico', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785373001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785373001.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785373001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25673, 'Don Jaime I, 1968', 'Imagen de la unidad n‚î¨‚ïë 164 (serie 150, o topolinos), de la l‚îú¬°nea tranviaria 4 ("Arrabal") encaminada hacia la plaza de la Seo. Esta unidad se activaba cuando las dos tranv‚îú¬°as "oficiales" de la l‚îú¬°nea (el 223, y el 228) estaban averiados, como parece ser el caso. A la izquierda, el acceso desde el puente de Piedra. Detr‚îú√≠s, el multifuncional edificio del arzobispado, antiguo Seminario Conciliar, ahora ocupado, entre otros, por Radio Popular, y por el cine Pax. A la derecha, quiosco y densa arboleda de la plaza de la Seo. Fuente visual: trotskeetravel.com/, a trav‚îú¬Æs de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170380711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170380711.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170380711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25676, 'Lonja c.1925', 'Imagen de la Lonja, despejada de las antiguas Casas de la Ciudad (ayuntamiento), estrat‚îú¬Ægica entre las calles de don Jaime I y del Pilar, y el paseo del Ebro. Fuente visual: "Casa Lonja. Exterior", en √î√á¬£El arte en Espa‚îú‚ñía. Zaragoza, con texto de Anselmo Gasc‚îú‚îÇn de Gotor. Edici‚îú‚îÇn Thomas. Patronato Nacional de Turismo.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33515081093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33515081093.webp', 'https://www.flickr.com/photos/zaragozaantigua/33515081093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25683, 'Calle de Don Jaime I 1968', 'Veraniega imagen capturada en la calle de Don Jaime I ( (original cardo de la Cesaraugusta romana) y centrada en el troleb‚îú‚ïës n‚î¨‚ïë 14 modelo BUT London (ubicaci‚îú‚îÇn del volante a la diestra) de un piso realizando el trayecto de regreso en la l‚îú¬°nea G‚îú√≠llego y en direcci‚îú‚îÇn al tramo medio del Coso. De fondo edilicio, el antiguo seminario metropolitano, que entonces albergaba diversas dependencias del arzobispado, como Radio Popular y el cine Pax (que reestrenaba la comedia "Tres en un sof‚îú√≠"), am‚îú¬Æn de la sucursal de una importante local caja de ahorros. Hacia la derecha se abre la plaza de La Seo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65552700, -0.87653500, '0101000020E61000005B94D920930CECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51570599902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51570599902.webp', 'https://www.flickr.com/photos/zaragozaantigua/51570599902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20883, 'La Seo s. XIV', 'Dibujo de Francisco ‚îú√¨‚îú‚ñíiguez, 1937. La recreaci‚îú‚îÇn representa el templo en su ‚îú¬Æpoca mud‚îú¬Æjar. La tesis oficial no contempla que la actual torre barroca utilizara el emplazamiento del alminar octogonal de la mezquita mayor de Saraqusta, pero algunos investigadores sostienen esa opci‚îú‚îÇn. Fuente: sites.google.com/site/zagralandalus/los-alminares-de-la-seo, a trav‚îú¬Æs de www.facebook.com/photo.php?fbid=1864645023755215&set=...', 1350, 1300, 1399, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65524300, -0.87609700, '0101000020E610000073F56393FC08ECBF6AF7AB00DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30682686311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30682686311.webp', 'https://www.flickr.com/photos/zaragozaantigua/30682686311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20891, 'Gran Cloaca ca. 20', 'La ‚î¨¬ΩGran Cloaca‚î¨‚ïó del foro romano de Caesaraugusta resurgi‚îú‚îÇ al levantar en 1982 la plaza de La Seo. Un siglo antes (1870) ya se dio con ella. Hoy se encuentra conservada como una estructura m‚îú√≠s del Museo del Foro de Caesaraugusta. Fue realizada a finales del reinado de Augusto, o comienzos del de Tiberio, entre el a‚îú‚ñío 10 y el 20 de la Era, como parte del sistema de saneamiento y evacuaci‚îú‚îÇn de aguas del nuevo foro. Construida en opus caementicium, se cubri‚îú‚îÇ con b‚îú‚îÇveda de medio ca‚îú‚ñí‚îú‚îÇn. La altura interior es de 2.64 m. y la luz de 1.78 m. El espesor de las paredes es de 60 cm. En la imagen, vista parcial de los restos de la "Gran Cloaca" al aire en la plaza de la Seo. Archivo Luis Serrano. Fuente: "El Ebro", Ediciones Oroel, 1986.', NULL, NULL, NULL, NULL, 'CASCO HIST‚îú√¥RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16814002841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16814002841.webp', 'https://www.flickr.com/photos/zaragozaantigua/16814002841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21138, 'Plaza de La Seo c.1895', '"Vista de la Catedral de San Salvador (La Seo)", y de la Plaza de la Seo, desde altura. Fuente visual: Esudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65516600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFBFB9BF7ADCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14745087029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14745087029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14745087029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21139, 'Plaza de La Seo c.1895', 'Vista de la Lonja de mercaderes desde la plaza de La Seo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65519000, -0.87621800, '0101000020E61000003354C554FA09ECBF47551344DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750916237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750916237.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750916237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21150, 'Plaza de La Seo c.1895', '"La Lonja". Foto Colecci‚îú‚îÇn Universidad Michel de Montaigne, Burdeos. Toma de la plaza de la Seo de Zaragoza, mirando hacia la Lonja, cuando el antiguo edificio de viviendas (esquina entre la calle del Pilar y Don Jaime, a la izquierda) a‚îú‚ïën estaba intacto. A la derecha, edificio del arzobispado. La fuente de la Samaritana, con utilidad no s‚îú‚îÇlo est‚îú¬Ætica. Mediados de la d‚îú¬Æcada de 1890. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704539937.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704539937.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704539937/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21166, 'Plaza de La Seo c.1895', 'Imagen de la plaza de la Seo centrada en la fuente de la Samaritana cuando era el acu‚îú√≠tico epicentro de una notable foresta, y a su funci‚îú‚îÇn est‚îú¬Ætica se un‚îú¬°a la funcional de proveedora de agua. Hab‚îú¬°a sido instalada en 1866. A la izquierda, la Lonja y la Casa Consistorial. Enfrente, tras la de Samaria, el Seminario Conciliar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23025287529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23025287529.webp', 'https://www.flickr.com/photos/zaragozaantigua/23025287529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21198, 'Plaza de La Seo 1890', 'Coloreada imagen capturada desde la altura del inmueble del n‚î¨‚ïë 3 de la plaza de La Seo con una interesante vista de la antigua plaza y su entorno, dominado por la esbelta torre barroca de la catedral del Salvador en su Epifan‚îú¬°a y su clasicista fachada que decora el ingreso por la puerta occidental del templo. A la izquierda, el Arco del Arzobispo que comunica con el hom‚îú‚îÇnimo palacio. La plaza aparece vertebrada alrededor, en primer t‚îú¬Ærmino, de la fuente de la Samaritana, realizada en la fundici‚îú‚îÇn Averly.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65534200, -0.87643800, '0101000020E6100000BE175FB4C70BECBFFDD8243FE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425457922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425457922.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425457922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21241, 'Calle Don Jaime c.1900', 'Grupo de tres hombres caminando tranquilamente por la calle de Don Jaime I de Zaragoza. Al fondo, el cruce con la calle del Pilar y la Lonja. Fuente: www.facebook.com/photo.php?fbid=1668897606655861&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894433228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894433228.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894433228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21242, 'Plaza de La Seo c.1900', 'Plaza de La Seo de Zaragoza, vista desde la calle de Don Jaime I. A la izquierda, el Palacio Arzobispal y el Arco del Arzobispo. En el centro, la estatua de la Samaritana ante la catedral. Fuente: www.facebook.com/photo.php?fbid=1668896829989272&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057509096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057509096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057509096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22482, 'Av. Compromiso de Caspe 1962', 'Tranquila imagen capturada en el antiguo camino de las Fuentes, ya redenominado como avenida del Compromiso de Caspe y centrada en el tramo de los impares (a la derecha) entre las recientes calles Doctor Iranzo y Obispo Laplana, poco antes de Salvador Minguij‚îú‚îÇn, que entonces se‚îú‚ñíalaba el "nec plus ultra" de la ciudad en esta perif‚îú¬Ærica barriada. Hacia el fondo de la imagen, el lejano principio de la avenida desde la calle de Miguel Servet. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64538000, -0.86299400, '0101000020E61000007C9DD497A59DEBBF0ABFD4CF9BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39282866304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39282866304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39282866304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23647, 'Aer‚îú‚îÇdromo Sanjurjo 1939', 'El Aer‚îú‚îÇdromo Sanjurjo, en Garrapinillos, fue habilitado como base a‚îú¬Ærea a comienzos de 1937 por los nacionalistas, en un estrat‚îú¬Ægico emplazamiento desde el que poder intervenir r‚îú√≠pidamente en los principales frentes de guerra. En ‚îú¬Æl se aposent‚îú‚îÇ importante n‚îú‚ïëmero y calidad de aviones de la Legi‚îú‚îÇn C‚îú‚îÇndor alemana, y de la Legionaria italiana. Fue tal su importancia, que en octubre de 1937 un escuadr‚îú‚îÇn de "Chatos" y "Moscas" republicanos lo atacaron, destruyendo y da‚îú‚ñíando entre 17 y 30 aviones de los facciosos. En la imagen, una l‚îú¬°nea de cazas Fiat CR-32 de la Aviaci‚îú‚îÇn Legionaria Italiana, en los ‚îú‚ïëltimos d‚îú¬°as de la guerra. Al fondo, un polivalente Ju-52 y un bombardero He-111 de la Legi‚îú‚îÇn C‚îú‚îÇndor. A‚îú‚ñíos despu‚îú¬Æs, a los aviones alemanes e italianos se les a‚îú‚ñíadir‚îú¬°an los de la fuerza a‚îú¬Ærea de los Estados Unidos de Norteam‚îú¬Ærica. Fuente visual: www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18009158285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18009158285.webp', 'https://www.flickr.com/photos/zaragozaantigua/18009158285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21335, 'Plaza de La Seo 1903', 'Grabado que recoge el paso del Rosario que, proveniente de la calle de Don Jaime I, da una vueltecilla a la plaza de la Seo para encaminarse luego a la calle del Pilar la noche del 18 de octubre de 1903, en el marco de la visita a Zaragoza del rey Alfonso XIII, que presidi‚îú‚îÇ su paso desde el balc‚îú‚îÇn central del Palacio Arzobispal (a la izquierda) habilitado como morada real durante su estancia de tres d‚îú¬°as. La plaza de La Seo y la fachada del palacio fueron iluminadas para tal ocasi‚îú‚îÇn por la compa‚îú‚ñí‚îú¬°a Electro Peral Zaragozana. En el centro de la escena aparece la carroza titulada "la Venida de la Virgen", tallada en madera por el escultor Francisco de Borja ese mismo a‚îú‚ñío y que hac‚îú¬°a aqu‚îú¬° su estreno, siendo la ‚îú‚ïënica figura de este Rosario que no es de cristal. Aparece portada por 32 j‚îú‚îÇvenes con t‚îú‚ïënicas blancas y escoltados por todos los ac‚îú‚îÇlitos de los templos de Zaragoza que portaban pebeteros en los que se quemaba incienso y mirra. Tras ella, la carroza que representa a la bas‚îú¬°lica del Pilar, creada por Policarpo Valero y Bernab‚îú¬Æ y ampliado a las cuatro torres en 1895 por Le‚îú‚îÇn Quintana y Bianchi. A la derecha, vista de uno de los dos faroles con forma de le‚îú‚îÇn, obra del taller de hojalateros y vidrieros de los Tiesto y construido en 1865-1866.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65527000, -0.87635200, '0101000020E61000001A187959130BECBF64062AE3DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52539891386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52539891386.webp', 'https://www.flickr.com/photos/zaragozaantigua/52539891386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21358, 'Plaza de La Seo 1900', 'Imagen centrada en la fachada occidental de la Seo, flanqueada por el Arco del Arzobispo a la izquierda y la torre del templo. La escena incluye una vista parcial de la plaza de La Seo y, en primer t‚îú¬Ærmino, el empedrado paso peatonal por el arranque de la calle de Don Jaime I, donde destaca el tendido tranviario que por 10 c‚îú¬Æntimos y desde la plaza de la Constituci‚îú‚îÇn conduce hacia la izquierda al Arrabal por el Puente de Piedra.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785682811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785682811.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785682811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21363, 'Plaza de La Seo c.1910', 'AHPZ-Archivo Coyne, 1907-1930. Plaza de la Seo.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65509400, -0.87628300, '0101000020E6100000F94D61A5820AECBF25E7C41EDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877890581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877890581.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877890581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21744, 'La Seo 1938', 'Tras dos a‚îú‚ñíos de ocultamiento por parte del bando franquista, en 1938 se revel‚îú‚îÇ la muerte de Jos‚îú¬Æ Antonio Primo de Rivera, l‚îú¬°der de la Falange fusilado en Alicante el 20 de noviembre de 1936. En la imagen, profusi‚îú‚îÇn de coronas de flores al pie de la torre de la Seo, con motivo del funeral celebrado en noviembre de 1938 en memoria del pol‚îú¬°tico fascista. Fuente: Archivo Heraldo de Arag‚îú‚îÇn.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21841817375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21841817375.webp', 'https://www.flickr.com/photos/zaragozaantigua/21841817375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21772, 'Plaza La Seo 1932', 'Plaza de la Seo y Fuente de la Samaritana. Al fondo, el Pilar. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854992097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854992097.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854992097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21814, 'Calle Pabostr‚îú¬°a 1934', 'Imagen de la procesi‚îú‚îÇn del Domingo de Ramos 25 de marzo de 1934, reproducida en la revista Blanco y Negro en abril de 1935. Los palmeros desfilan por la calle de la Pabostr‚îú¬°a, con la de Diego Dormer al fondo. Fuente: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65444100, -0.87617200, '0101000020E61000001C78B5DC9909ECBFAD1402B9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30702428252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30702428252.webp', 'https://www.flickr.com/photos/zaragozaantigua/30702428252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21965, 'Plaza del Pilar 1949', 'Imagen de la despejada plaza del Pilar en su reciente ampliaci‚îú‚îÇn por derribo entre Don Jaime I (izquierda), y el edificio del Gobierno Civil en construcci‚îú‚îÇn (a la derecha, fuera de plano). La imagen se ha capturado desde la puerta de la Lonja. Enfrente, el nuevo edificio del n‚î¨‚ïë 16 de la plaza, esquinero con Don Jaime I, el primero de los tres de ese tramo. A su derecha, las traseras de los nuevos 25 y 27 de la calle Santiago, y por el solar del 23, visual de las antiguas viviendas a‚îú‚ïën sin derribar del 30-32, a la derecha del Palacio de Montemuzo. En la plaza, autobuses de l‚îú¬°nea regular entre Zaragoza y el entorno municipal y provincial. Fuente Visual: Fotos Ysa, Archivo P‚îú‚ïëblico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65541700, -0.87696300, '0101000020E610000061AA99B51410ECBF081F4AB4E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22177307702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22177307702.webp', 'https://www.flickr.com/photos/zaragozaantigua/22177307702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22081, 'Calle Pabostr‚îú¬°a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostria, capturada desde su arranque en la calle Dormer n‚î¨‚ïë 8. A la izquierda, la Puerta Sur, o de la Pabostr‚îú¬°a de la Catedral de El Salvador, medieval acceso en desuso. La denominaci‚îú‚îÇn de "pabostr‚îú¬°a" hac‚îú¬°a referencia a la cercana residencia del encargado de la hacienda y los bienes temporales de la catedral. Desde antiguo, este cargo fue teniendo varias denominaciones: "Procuraci‚îú‚îÇn", "Mensa Com‚îú‚ïën", "Mensa Capitular", "Prepositura", y "Pabostr‚îú¬°a". El que tiene la llave de la caja, en plata.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65446100, -0.87629900, '0101000020E6100000658F5033A40AECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15760216592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15760216592.webp', 'https://www.flickr.com/photos/zaragozaantigua/15760216592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22128, 'Pl. de la Seo c.1959', 'Plaza de La Seo. Al fondo, el edificio sin terminar del nuevo Ayuntamiento, y el Pilar. En primer t‚îú¬Ærmino, las v‚îú¬°as de la tranviaria l‚îú¬°nea del Arrabal. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159778261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159778261.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159778261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22200, 'Pl. de La Seo 1954', 'Imagen de la plaza de la Seo capturada desde los jardines que hubiera en la ampliada plaza del Pilar, en el tramo desde la nueva Casa Consistorial, y hasta la calle de Don Jaime I, al fondo. Por esta calle, precisamente, transita un troleb‚îú‚ïës (posiblemente el n‚î¨‚ïë 15, un Vectra-Escoriaza) de la l‚îú¬°nea del G‚îú√≠llego, en su retorno a la terminal del Coso. Fuente visual: archivo Heraldo de Arag‚îú‚îÇn, en "Padre Ebro. El r‚îú¬°o Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33572915190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33572915190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33572915190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22359, 'Plaza de La Seo 1961', '"Plaza de la Catedral", ‚îú‚îÇleo sobre lienzo, Alberto P‚îú¬Ærez Piqueras, 1961. Premio Goya en el concurso Arte zaragozano actual de 1962. Representaci‚îú‚îÇn neocubista de la plaza de La Seo de Zaragoza, con el Palacio Arzobispal al fondo, la fuente de la Samaritana y la entrada a la catedral. Fuente: Colecci‚îú‚îÇn del Ayuntamiento de Zaragoza.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65530900, -0.87635300, '0101000020E6100000310C5872150BECBF22E3512AE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20886096742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20886096742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20886096742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22833, 'Foro Romano c.1989', 'En 1980, durante los trabajos de restauraci‚îú‚îÇn en La Seo, se hall‚îú‚îÇ una cloaca cuya funci‚îú‚îÇn era la de recoger las aguas ca‚îú¬°das de la plaza del templo del Foro romano. Ese mismo a‚îú‚ñío se hallaba tambi‚îú¬Æn otra cloaca en la calle de Don Jaime. En 1982, los arque‚îú‚îÇlogos localizaron el sistema de desag‚îú‚ïùe de las termas que se hallan (musealizadas) en la calle de San Juan y San Pedro. Entre 1988 y 1994, con las excavaciones arqueol‚îú‚îÇgicas en la plaza de La Seo (1988-1991) y solares contiguos (1991-1994), se complet‚îú‚îÇ el conocimiento de los canales y cloacas al servicio del Foro de Caesaraugusta. Hay 30 cloacas registradas arqueol‚îú‚îÇgicamente en la ciudad, cuyo conjunto es superior a los 600 metros de longitud. En la imagen, el subsuelo de la Plaza de la Seo levantado, excavado, y estudiado. A la izquierda, fuera del per‚îú¬°metro arqueol‚îú‚îÇgico, la base de la Torre de la Seo.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65524600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFDB6AD619DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754262510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754262510.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754262510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22911, 'Plaza La Seo c.1988', 'Excavaci‚îú‚îÇn arqueol‚îú‚îÇgica del foro romano en la plaza de La Seo. Al fondo, en el centro, calle de Don Jaime I. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150712055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150712055.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150712055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22912, 'Plaza La Seo c.1988', 'Excavaci‚îú‚îÇn arqueol‚îú‚îÇgica del foro romano. Al fondo, la plaza del Pilar. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23186574831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23186574831.webp', 'https://www.flickr.com/photos/zaragozaantigua/23186574831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22935, 'La Seo 1989', 'Vista nocturna de las excavaciones arqueol‚îú‚îÇgicas en la plaza de La Seo, con la catedral al fondo, en 1989. Esta prospecci‚îú‚îÇn tuvo lugar entre 1988 y 1991, dando como resultado el museo del Foro Romano. Fuente: "La plaza de La Seo. Zaragoza. Investigaciones Hist‚îú‚îÇrico-Arqueol‚îú‚îÇgicas". Ayuntamiento de Zaragoza, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32171401686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32171401686.webp', 'https://www.flickr.com/photos/zaragozaantigua/32171401686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23850, 'Pl. de la Seo c.1955', 'Imagen de la nocturna procesionaria confesional del Rosario de Cristal, con detalle del "paso" del legendario (fant‚îú√≠stico) ni‚îú‚ñío-m‚îú√≠rtir Dominguito de Val, santificado por la rama m‚îú√≠s antisemita y medieval del catolicismo, que lo mantiene en su devocionario aun despu‚îú¬Æs del Concilio Vaticano II. A su vera, sus patrocinados y canoros "infanticos". La captura se ha realizado en la plaza de la Seo, junto a las desaparecidas Casas de los Infantes de la Seo, que quedan a la izquierda, fuera de plano. Al fondo, a la derecha, las a‚îú¬Æreas y visuales jaculatorias de ne‚îú‚îÇn instaladas en el templo metropolitano del Pilar al comienzo de la d‚îú¬Æcada, para facilitar el acompa‚îú‚ñíamiento a la jaculatoria oral que suena, tres veces al d‚îú¬°a, desde el a‚îú‚ñío del se‚îú‚ñíor de 1940, A‚îú‚ñío II de la Victoria. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26620438382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26620438382.webp', 'https://www.flickr.com/photos/zaragozaantigua/26620438382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23994, 'Milagro del Ni‚îú‚ñío-Hostia 1427', 'Pintura del siglo XVII situada en el pa‚îú‚ñío lateral izquierdo de la capilla de Santo Dominguito de Val de la Seo de Zaragoza, atribuida por Jos‚îú¬Æ Cam‚îú‚îÇn Aznar a Bartolom‚îú¬Æ Vicente. Procesi‚îú‚îÇn en la plaza del la Seo de Zaragoza, en la que el arzobispo Alonso de Arg‚îú‚ïùello, que lo fue entre 1419 y 1429, porta en brazos bajo palio al Ni‚îú‚ñío Jes‚îú‚ïës, para llevarlo a la catedral. La leyenda narra que una mujer casada consult‚îú‚îÇ a un alfaqu‚îú¬° (doctor en leyes musulm‚îú√≠n, considerado mago) para eliminar los malos tratos que le propinaba su marido. El remedio aconsejado fue procurarse una hostia consagrada. La mujer comulg‚îú‚îÇ en San Miguel sin tragarse la hostia, y la meti‚îú‚îÇ en un cofre. Al abrirlo hab‚îú¬°a un ni‚îú‚ñío, que el alfaqu‚îú¬° orden‚îú‚îÇ quemar. El ni‚îú‚ñío sali‚îú‚îÇ ileso y se lo contaron al obispo, que organiz‚îú‚îÇ la procesi‚îú‚îÇn. Dejaron al ni‚îú‚ñío en el altar de la capilla de San Valero y al d‚îú¬°a siguiente en una misa, el ni‚îú‚ñío se volvi‚îú‚îÇ a convertir en hostia y el obispo se la trag‚îú‚îÇ. En la imagen, la comitiva municipal sigue al palio detr‚îú√≠s de un grupo de capitulares. A la derecha, los maceros. Al fondo, la supuesta puerta de la Seo, aunque la c‚îú‚ïëpula que se ve detr‚îú√≠s recuerda a la que ten‚îú¬°a la Diputaci‚îú‚îÇn del Reino. Fuente visual: "El municipio en Arag‚îú‚îÇn", DPZ, 2004.', 1427, 1427, 1427, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20549754211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20549754211.webp', 'https://www.flickr.com/photos/zaragozaantigua/20549754211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24227, 'Pl. de la Seo c.1955', '"Rosario de Cristal. Paso de Santo Dominguito de Val. Infanticos. Gente". De las antiguas (y desaparecidas) Casas de los Infantes de la Seo, en la plaza de la Seo, sale el procesional y confesional paso del legendario ni‚îú‚ñío-m‚îú√≠rtir. El artificio luminario para capturar la nocturna escena atrae miradas y gestos. La del guardia, no. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65504000, -0.87637300, '0101000020E6100000F71DC3633F0BECBF32C9C859D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22463231459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22463231459.webp', 'https://www.flickr.com/photos/zaragozaantigua/22463231459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23685, 'Aer‚îú‚îÇdromo Sanjurjo 1939', 'Imagen capturada en el Aer‚îú‚îÇdromo Sanjurjo y centrada en un aeroplano alem‚îú√≠n modelo Messerschmitt Bf 108 B, utilizado en funciones de comunicaci‚îú‚îÇn, enlace y correo por el Grupo de Bombardeo K-88 de la Legi‚îú‚îÇn Condor. Desde finales de 1937, durante la Batalla de Teruel, y hasta la campa‚îú‚ñía de Catalu‚îú‚ñía, a principios de 1939, este fue uno de los aer‚îú‚îÇdromos utilizados por el contingente alem‚îú√≠n enviado por la Alemania nazi para respaldar a los sublevados nacionalistas en la guerra civil, sobre todo como base de bombarderos.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49561229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49561229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/49561229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24591, 'Plaza de la Seo 1976', 'Al fondo, la Lonja como espectacular marco esc‚îú¬Ænico de la exposici‚îú‚îÇn Arte fara‚îú‚îÇnico, organizada por la Direcci‚îú‚îÇn General de Bellas Artes del Patrimonio Art‚îú¬°stico Cultural, e integrada por 219 piezas leg‚îú¬°timamente egipcias procedentes del antiguo territorio del Nilo, primero expuestas en Madrid, luego en Zaragoza, y finalmente en Barcelona. Por encima y a la izquierda, emerge la torre de Santa Leonor del Pilar, con su fluorescente jaculatoria. En primer t‚îú¬Ærmino, la plaza de La Seo con la humidificante fuente que en 1962 sustituy‚îú‚îÇ a la entra‚îú‚ñíable y tradicional de La Samaritana, que primero viaj‚îú‚îÇ al parque de Bruil para terminar en la plaza del Justicia. Tras ella, el tradicional quiosco de prensa anunciando entre otras las revistas masculina y femenina del boyante Opus Dei, y dos personas mayores tomando el sol en un banco, en una ma‚îú‚ñíana bien fresca.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16659900758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16659900758.webp', 'https://www.flickr.com/photos/zaragozaantigua/16659900758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24592, 'Lonja-Ayuntamiento c.1888', 'La calle de la Lonja con su activo ritmo vital cotidiano como continuaci‚îú‚îÇn del puente de Piedra que comunica con el Arrabal, al fondo. Un tranv‚îú¬°a "de sangre", carros tirados por caballer‚îú¬°as, y un heterog‚îú¬Æneo grupo de viandantes, bullen en el entorno de la Lonja y la Casa Consistorial. La plaza de la Seo, inmediata, se abre a la derecha. La calle del Pilar, a la izquierda. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23366682236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23366682236.webp', 'https://www.flickr.com/photos/zaragozaantigua/23366682236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24594, 'La Lonja 1901', 'Grupo de personas ante la Lonja, en la confluencia de la calle de Don Jaime I con la del Pilar. Fuente: www.delcampe.net', 1901, 1901, 1901, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28512100995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28512100995.webp', 'https://www.flickr.com/photos/zaragozaantigua/28512100995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24597, 'Plaza de la Seo 1902', 'Imagen capturada junto a la fuente denominada Samaritana en la antigua plaza de la Seo, erigida no como mero ornato visual, sino como destacado punto de provisi‚îú‚îÇn del l‚îú¬°quido elemento para consumo de boca, como manifiesta la nutrida parroquia congregada en torno a ella, si bien parece que son las mujeres las que, provistas de c‚îú√≠ntaros de diversas capacidades, efectivamente realizan esa funci‚îú‚îÇn, mientras los ind‚îú¬°genas parecen estar vareando el agua de forma est‚îú‚îÇlida. Al fondo de la imagen, la calle de la Lonja y el desemboque en ella de la estilizada calle del Pilar, donde destaca el edificio de la casa de la Lonja como antigua dependencia anexa a la casa del Ayuntamiento. Esta imagen fue comercializada como vista estereosc‚îú‚îÇpica de la ciudad bajo el t‚îú¬°tulo "The old Exchange (1551) and Plaza de La Seo, Saragossa, Spain", cuando la Lonja era curiosamente catalogada como "mercado burs‚îú√≠til". Fuente visual: Underwood & Underwood Publishers (Estados Unidos de Norteam‚îú¬Ærica), en Zaragoza estereosc‚îú‚îÇpica, fotograf‚îú¬°a profesional y comercial 1850-1970, PUZ.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34255489843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34255489843.webp', 'https://www.flickr.com/photos/zaragozaantigua/34255489843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24603, 'Plaza de La Seo 1902', 'Imagen estereosc‚îú‚îÇpica capturada en la plaza de La Seo con el fondo de la "old Exchange" (Lonja) entre la calle del Pilar (cuya esquina aparece ensanchada tras el derribo de las inmediatas casas) y el paseo del Ebro. En primer t‚îú¬Ærmino, la fuente de la Samaritana en su original ubicaci‚îú‚îÇn de la plaza como importante punto de suministro de agua. A la derecha, el seminario ,metropolitano conciliar.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65539800, -0.87639500, '0101000020E6100000EC17EC866D0BECBF91EEE714E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51422225697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51422225697.webp', 'https://www.flickr.com/photos/zaragozaantigua/51422225697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24604, 'Plaza de La Seo 1878', 'Imagen capturada por el fot‚îú‚îÇgrafo villanovense Gregorio Sabat‚îú¬Æ F‚îú¬Ærriz e integrada en el ‚îú√≠lbum "Vistas de Zaragoza", centrada en una vista del entorno de la plaza de La Seo tomada desde la altura de la vivienda del Cabildo adosada a la cara suroeste de la torre de la catedral y a la capilla de las santas Justa y Rufina. En primer t‚îú¬Ærmino, la plaza de La Seo con sus jardines y ‚îú√≠rboles vertebrados en torno a la Fuente de la Samaritana instalada en 1866. A la derecha, fachada del Seminario Conciliar construido sin demasiados remilgos sobre los restos del Palacio de la Diputaci‚îú‚îÇn del Reino de Arag‚îú‚îÇn, que fueron arrasados para la ocasi‚îú‚îÇn. Al fondo y a la izquierda, viviendas de la manzana de la calle de Don Jaime I comprendida entre las calles del Pilar y de Juan Mart‚îú¬°n Goicoechea. Aqu‚îú¬° figuran la n‚îú‚ïëmero 7, esquinera con la calle del Pilar, y su vecina la n‚îú‚ïëmero 9. Al otro lado de esa calle, la Casa-Lonja anexa a la Casa Consistorial como escenario de diversas actividades municipales y tambi‚îú¬Æn anual espacio donde se proced‚îú¬°a a la "declaraci‚îú‚îÇn de soldados" de los individuos que de forma obligatorio formaban parte del reemplazo de quintas (incluyendo entre ellos a quienes no pod‚îú¬°an permitirse la redenci‚îú‚îÇn en met‚îú√≠lico del servicio o aquellos que acud‚îú¬°an como "sustitutos" de los se‚îú‚ñíoritos y privilegiados) y que deb‚îú¬°an "ingresar en caja" en torno al 1 de mayo para cumplir con los preceptivos cuatro a‚îú‚ñíos de "servicio activo".', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54760597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54760597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/54760597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24607, 'Calle Dormer a‚îú‚ñíos 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. Calle Diego Dormer y La Torre de la Seo [o Catedral del Salvador en su Epifan‚îú¬°a, al fondo]". A la izquierda, el Palacio renacentista conocido como casa de Miguel Donlope o de la Real Maestranza de Caballer‚îú¬°a, por servir de sede a esta Corporaci‚îú‚îÇn zaragozana. Construido durante la tercera y cuarta d‚îú¬Æcada del siglo XVI es un ejemplo del modelo de casa-palacio aragon‚îú¬Æs. Fuente visual: Archivo W‚îú‚ïùnderlich (WUN-05815) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65435600, -0.87653500, '0101000020E61000005B94D920930CECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14876971170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14876971170.webp', 'https://www.flickr.com/photos/zaragozaantigua/14876971170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24609, 'Torre de la Seo sin chapitel 1860', 'Un rayo incendi‚îú‚îÇ el chapitel de la torre de la Seo en 1850, matando al campanero. Hasta 1861 no se empez‚îú‚îÇ a colocar el nuevo chapitel, fundido en los talleres Julio Goybet y C‚îú¬°a. de Zaragoza. La peque‚îú‚ñía torrecilla a la izquierda de la demediada torre de La Seo ser‚îú¬°a la ins‚îú‚îÇlita torre de la desaparecida iglesia de Santiago, sita en la calle Don Jaime I. M‚îú√≠s informaci‚îú‚îÇn sobre el suceso: tausiet.blogspot.com/2016/01/rayo-sobre-la-seo-muerte-de-... Fuente visual: Mariano J‚îú‚ïëdez y Ortiz. 1859-1860. ‚îú√ºlbum: Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Col. Mariano Mart‚îú¬°n Casalderrey, Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65470400, -0.87610700, '0101000020E6100000567E198C1109ECBFBB473657CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896850475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896850475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896850475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24613, 'Palmeros en La Seo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 07/04/1974. Palmeros en procesi‚îú‚îÇn de palmas en la plaza de la Seo. A la izquierda, la catedral, con espacios se‚îú‚ñíalados en suelo para aparcar en bater‚îú¬°a. Al fondo, la callejuela Ram‚îú‚îÇn Cu‚îú¬Ællar. A la derecha, antiguo edificio residencial de la plaza con el bar "La Cadiera" en la esquina.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65522200, -0.87608900, '0101000020E6100000BD546CCCEB08ECBF53CF8250DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048052115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048052115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048052115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24618, 'Calle del Pilar a‚îú‚ñíos 20', 'Calle del Pilar (derecha), esquina con la de Don Jaime I, desde la plaza de la Seo. El edificio comercial que centra la imagen tuvo distintos usos: aqu‚îú¬° parece ofrecer obras art‚îú¬°sticas de recuerdo, o souvenirs, de escultura, pintura, artesan‚îú¬°a. Luego fue cafeter‚îú¬°a y tienda de ultramarinos (Pedro Santamera), hasta desaparecer con la manzana de la que formaba parte, cuando los numerosos derribos para dar paso a la nueva gran plaza del Pilar. Fuente visual: Cr‚îú‚îÇnica de Zaragoza 1900-1920.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65542400, -0.87667200, '0101000020E610000087342A70B20DECBFBA8102EFE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15472718210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15472718210.webp', 'https://www.flickr.com/photos/zaragozaantigua/15472718210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24619, 'Dormer 1973', 'Archivo Municipal. Gerardo Sancho Ramo. Julio 1973. Los "Gigantes", como los "Cabezudos", no pisan mucho las calles en julio, pero ese a‚îú‚ñío estaba justificada la sofoquina: se estaban rodando im‚îú√≠genes para la pel‚îú¬°cula "Gigantes y Cabezudos", basada en la zarzuela del mismo t‚îú¬°tulo, y uno de los fragmentos recog‚îú¬°a, precisamente, la Salida de los Gigantes y Cabezudos en el entorno de La Seo y la actual plaza de San Bruno, mientras sonaban acordes musicales asociados, y la interpretaci‚îú‚îÇn de √î√á¬£Cuando era ni‚îú‚ñía y jugaba√î√á√ò. Esta pel‚îú¬°cula estaba producida por TVE, dirigida por Jos‚îú¬Æ Antonio P‚îú√≠ramo, y actuada (las piezas musicales estaban dobladas) por destacadas personalidades de la interpretaci‚îú‚îÇn. Se estren‚îú‚îÇ de octubre de ese a‚îú‚ñío, con gran ‚îú¬Æxito. En la imagen, durante una pausa del rodaje la chiquiller‚îú¬°a juega entre los Gigantes, que descansan junto a la calle Dormer, en el antiguo barrio de la Seo.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65458900, -0.87626600, '0101000020E6100000761893FE5E0AECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476308213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476308213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476308213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24625, 'Roscones 1916', 'Foto S‚îú√≠nchez Rom‚îú√≠n. La Hormiga de Oro, febrero de 1916. Venta de roscones el d‚îú¬°a de San Valero en la puerta de la Seo de Zaragoza, el 29 de enero de 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18530408643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18530408643.webp', 'https://www.flickr.com/photos/zaragozaantigua/18530408643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24626, 'Gran cloaca de Caesar Augusta siglo I', '‚îú√´poca de Tiberio. 14-37 d.C. Detalle del interior de la gran cloaca de Caesar Augusta bajo la actual plaza de La Seo. Se halla musealizada junto a los restos del foro. Desde el Renacimiento se utiliz‚îú‚îÇ como pasadizo subterr‚îú√≠neo, bodegas y despensas. Fuente: Cat‚îú√≠logo Aquaria. DPZ, 2006', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18676012115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18676012115.webp', 'https://www.flickr.com/photos/zaragozaantigua/18676012115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24631, 'Calle Pabostr‚îú¬°a 1971', 'Vista de la calle Pabostr‚îú¬°a con la de Dormer al fondo. A la derecha, puerta meridional de la Seo. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65444300, -0.87620300, '0101000020E6100000DD06B5DFDA09ECBF4E0CC9C9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528454243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528454243.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528454243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24634, 'Plaza La Seo ca. 1972', 'Plaza de la Seo, con imagen de la Lonja, el Ayuntamiento, y el Pilar. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22754253057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22754253057.webp', 'https://www.flickr.com/photos/zaragozaantigua/22754253057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24636, 'Calle Cisne 1972', 'Dos ni‚îú‚ñías cargadas de libros caminan por la calle del Cisne, antigua de Zaporta hasta 1863, hacia el final de la calle de Diego Dormer, al fondo. A la izquierda, anexas dependencias de la Seo, y a la derecha, inmuebles de los n‚îú‚ïëmeros 2 y 4 de la calle, y tapia del patio del palacio de la Real Maestranza de Caballer‚îú¬°a. El recoleto barrio de La Seo, peque‚îú‚ñío laberinto urbano milenario y descuidado, manten‚îú¬°a pese a ello la calma y el sabor.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65478000, -0.87649300, '0101000020E6100000A088450C3B0CECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23135317372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23135317372.webp', 'https://www.flickr.com/photos/zaragozaantigua/23135317372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24637, 'Plaza La Seo c.1972', 'Plaza de La Seo el d‚îú¬°a de San Valero. Al fondo, puente de Piedra. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150838895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150838895.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150838895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24638, 'Calle San Valero c.1972', 'La calle de San Valero, antigua de la Frener‚îú¬°a hasta 1863, se abre desde la de Don Jaime I, y conecta con la Seo. En la imagen, solares dejados tras derribo de los inmuebles de los n‚îú‚ïëmeros 5-7, 9 y 11, este ‚îú‚ïëltimo esquinero con la calle de Ram‚îú‚îÇn Cu‚îú¬Ællar. A la derecha, r‚îú‚îÇtulo de una popular taberna sita en el local del n‚î¨‚ïë 8, que perdura. Al fondo, rotunda, la catedral del Salvador, con a‚îú‚ñíejos anexos en la calle del Cisne, luego derribados.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65501200, -0.87683600, '0101000020E61000001893FE5E0A0FECBF683EE76ED7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158919212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158919212.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158919212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22737, 'C.‚î¨‚ïë de la Mosquetera 1973', 'Bicolor reba‚îú‚ñío de ovejas ramonea en un campo inmediato al camino de la Mosquetera y compone una t‚îú¬°pica visi‚îú‚îÇn de la periferia de la ciudad del momento, tomada a espaldas de la avenida de G‚îú‚îÇmez Laguna. De fondo esc‚îú¬Ænico, y de izquierda a derecha, viviendas del principio de la calle de Mar‚îú¬°a Guerrero, en el barrio de La Bozada; pabell‚îú‚îÇn de la Infanta Isabel y el de Pensionistas del arbolado Hospital Psiqui‚îú√≠trico Nuestra Se‚îú‚ñíora del Pilar; grandes bloques en construcci‚îú‚îÇn que a‚îú‚ñíos m‚îú√≠s tarde quedar‚îú√≠n en una esquinera ubicaci‚îú‚îÇn entre la prolongaci‚îú‚îÇn de la calle de la Duquesa de Villahermosa y la nueva V‚îú¬°a Universitas; y finalmente, a la derecha, el bloque del n‚î¨‚ïë 9 de la calle de Santa Rita de Casia. En el transcurso de unos cuantos a‚îú‚ñíos, este escenario conocer‚îú¬°a una radical transformaci‚îú‚îÇn. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64267000, -0.90821600, '0101000020E6100000A58636001B10EDBF670FB40243D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31481183387.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31481183387.webp', 'https://www.flickr.com/photos/zaragozaantigua/31481183387/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24640, 'Plaza de Santa Marta 1976', 'Imagen, desde la plaza de Santa Marta, del antiguo palacio del marquesado de Huarte. Este edificio se‚îú‚ñíorial fue construido a principios del siglo XVI seg‚îú‚ïën la planta est‚îú√≠ndar de las casonas nobles en la ciudad (gran patio central en torno al que se ordenan las estancias, con entrada por la antigua calle de Zaporta, luego Dormer, y esquina a Pabostria). A mediados del pasado siglo XX pas‚îú‚îÇ a propiedad de una entidad local de ahorro, hasta que a finales de los a‚îú‚ñíos 70 ‚îú¬Æsta negoci‚îú‚îÇ su conversi‚îú‚îÇn en sede estable del Archivo Hist‚îú‚îÇrico Provincial, hasta ese momento en el antiguo palacio de Sobradiel, sede del Colegio de Notarios. La imagen captura las obras de restauraci‚îú‚îÇn y acondicionamiento del antiguo palacio, que comenzar‚îú√≠ a funcionar como AHPZ en 1980, con documentaci‚îú‚îÇn desde el siglo X de la Era, hasta el XX. A la izquierda, la calle Dormer, el antiguo palacio de la Maestranza y, al fondo, la torre y catedral de la Seo. Fuente visual: Gerardo Sancho Ramo (Archivo P‚îú‚ïëblico Municipal).', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65420600, -0.87650100, '0101000020E610000056293DD34B0CECBF6A6CAF05BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23454505874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23454505874.webp', 'https://www.flickr.com/photos/zaragozaantigua/23454505874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24642, 'La Samaritana c.1920', 'Estatua y fuente de La Samaritana, en la plaza de La Seo. Al fondo, edificio del arzobispado. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65531700, -0.87632100, '0101000020E610000059897956D20AECBFA4C16D6DE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24287218474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24287218474.webp', 'https://www.flickr.com/photos/zaragozaantigua/24287218474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24645, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con la Lonja al fondo. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65542100, -0.87627800, '0101000020E610000087890629780AECBF490ED8D5E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619681880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619681880.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619681880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24646, 'Plaza de La Seo c.1920', 'Fuente de La Samaritana en la plaza de La Seo. Al fondo, edificio del arzobispado y Palacio Arzobispal. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803845901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803845901.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803845901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24647, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con el palacio arzobispal y la portada de la catedral al fondo a la derecha, tras el arbolado. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65528500, -0.87650300, '0101000020E61000008411FB04500CECBF9947FE60E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803983471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803983471.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803983471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24648, 'La Seo 1945', 'Sello sin valor postal para recaudar fondos destinados a la construcci‚îú‚îÇn del "Nuevo Seminario Conciliar de Casablanca" en 1945. En este caso, representa la plaza de La Seo, con un amenazante avi‚îú‚îÇn que se dirige a la torre de la catedral. Parece ser que pas‚îú‚îÇ de largo. Fuente: www.delcampe.net', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25475544561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25475544561.webp', 'https://www.flickr.com/photos/zaragozaantigua/25475544561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24649, 'Plaza de La Seo 1943', 'Foto: Josep Forns. Vista de la plaza de La Seo desde la del Pilar. Fuente: www.facebook.com/photo.php?fbid=10208829903638499&set...', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28145625660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28145625660.webp', 'https://www.flickr.com/photos/zaragozaantigua/28145625660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24654, 'Plaza de La Seo 1945', 'Imagen capturada desde la altura de la torre "Nueva", o de Nuestra Se‚îú‚ñíora del Pilar del hom‚îú‚îÇnimo templo, con el objetivo puesto en la Lonja, la plaza de la Seo, y la fachada de la catedral de San Salvador. En primer‚îú¬°simo plano, a la izquierda, vista parcial del cerrado per‚îú¬°metral en el que estaba prevista la construcci‚îú‚îÇn del nuevo ayuntamiento de la ciudad. Fuente visual: postal de la editorial "Soberanas", en www.ebay.es/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34435973965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34435973965.webp', 'https://www.flickr.com/photos/zaragozaantigua/34435973965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24656, 'Vista desde la Seo c.1916', 'Imagen capturada desde la altura de la torre barroca de la Seo, centrada en una vista hacia el sur urbano. En primer t‚îú¬Ærmino, tejados en el entorno de la recoleta plaza de Santa Marta, y a la derecha, traza de la calle de Don Jaime I, donde destaca el solar dejado tras el derribo de la antigua casa del conde de Atar‚îú¬Æs, en la esquina con la calle de Espoz y Mina, donde poco despu‚îú¬Æs se construir‚îú¬°a el referencial inmueble dise‚îú‚ñíado por Francisco Albi‚îú‚ñíana, que perdura. Hacia el fondo y siguiendo al calle, atalaya de la iglesia parroquial de San Gil Abad. Hacia la izquierda, la calle de San Jorge, donde destaca la nueva sede central de la Caja de Ahorros de Zaragoza, en la esquina con la calle de San Andr‚îú¬Æs, donde despunta levemente la torrecilla de esta peque‚îú‚ñía y hom‚îú‚îÇnima iglesia. Siguiendo la calle de San Jorge hacia la izquierda, emerge rotunda la antigua iglesia de San Pedro Nolasco, de planta de cruz griega. M‚îú√≠s hacia el fondo y a la derecha, el paseo de la Independencia. En el centro de la imagen, las torres de las dos centrales el‚îú¬Æctricas sitas en el entorno de la calle de San Miguel, sobre el fondo despejado de la antigua huerta de Santa Engracia que alcanza hasta la hom‚îú‚îÇnima iglesia parroquial.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65455700, -0.87673900, '0101000020E61000007B1684F23E0EECBF162F1686C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49105600518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49105600518.webp', 'https://www.flickr.com/photos/zaragozaantigua/49105600518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24895, 'La Samaritana c.1958', 'Plaza de La Seo con la fuente de la Samaritana fundida en Averly, trasladada en 1962 a la plaza del Justicia. Fuente. www.facebook.com/photo.php?fbid=808979045791389&set=o...', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65527500, -0.87619100, '0101000020E6100000CD9541B5C109ECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15204337611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15204337611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15204337611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25158, 'Calle Dormer a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste, mostrando la calle de Diego Dormer desde la plazuela de Santa Marta. Al fondo, la torre de la Seo. A la derecha, el palacio de la Real Maestranza de Caballer‚îú¬°a. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65443300, -0.87652600, '0101000020E61000008FFF0241800CECBF2A36E675C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061502870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061502870.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061502870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25159, 'Calle Cu‚îú¬Ællar a‚îú‚ñíos 30', 'Acuarela de Ambrosio del Ruste. Calle de Ram‚îú‚îÇn Cu‚îú¬Ællar, con la de San Valero al fondo. A la izquierda, calle del Cisne. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65481800, -0.87641900, '0101000020E61000000DFAD2DB9F0BECBF836A8313D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062251320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062251320.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062251320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25161, 'Calle Pabostr‚îú¬°a a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste, con una vista del palacio de la Real Maestranza de Caballer‚îú¬°a en la calle de Diego Dormer, al fondo, desde la de la Pabostr‚îú¬°a. A la derecha, puerta sur de la Seo. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65446500, -0.87630100, '0101000020E610000092770E65A80AECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062694170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062694170.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062694170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25165, 'Calle San Valero a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste. Al fondo de la calle San Valero, se distingue el lateral sur de la Seo. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65490600, -0.87673000, '0101000020E6100000AE81AD122C0EECBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32318536381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32318536381.webp', 'https://www.flickr.com/photos/zaragozaantigua/32318536381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25185, 'Plaza de La Seo 1909', '"Plaza de la Seo (Zaragoza)", ‚îú‚îÇleo sobre lienzo, Rafael Aguado Arnal, 1909. Colecci‚îú‚îÇn particular, Bilbao. Vista de la arbolada plaza de La Seo, con la catedral al fondo.', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65528900, -0.87634200, '0101000020E6100000368FC360FE0AECBFDB368C82E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52490931279.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52490931279.webp', 'https://www.flickr.com/photos/zaragozaantigua/52490931279/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25516, 'Paza de La Seo c.1897', 'Imagen capturada en la arbolada plaza de la Seo con motivo de la Solemnidad del Cuerpo y la Sangre de Cristo durante el protocolario desfile del Ayuntamiento en Corporaci‚îú‚îÇn, que abre una secci‚îú‚îÇn de la Guardia Municipal montada en traje de gala. Al fondo, fachada e ingreso principal de la Seo, desde donde sale la procesionaria. A la izquierda, el seminario conciliar, el palacio arzobispal y el arco del Arzobispo. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65536900, -0.87608300, '0101000020E6100000349C3237DF08ECBFF7E7A221E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25562239067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25562239067.webp', 'https://www.flickr.com/photos/zaragozaantigua/25562239067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25907, 'Plaza de la Seo 1970', 'Apacible imagen de la plaza de la Seo, cuando el articulado tranv‚îú¬°a 253, de la L‚îú¬°nea 10 "Academia" est‚îú√≠ presto a girar por la derecha para encaminarse al Puente de Piedra, tal y como ven‚îú¬°a haciendo desde los a‚îú‚ñíos sesenta. Un a‚îú‚ñío despu‚îú¬Æs de esta captura fotogr‚îú√≠fica, la l‚îú¬°nea ser‚îú¬°a clausurada, tras algo m‚îú√≠s de cuarenta a‚îú‚ñíos de servicio. Justo detr‚îú√≠s del tranv‚îú¬°a, el cine "Pax" proyecta el musical "Funny Girl", con Barbra Streisand, y Omar Sharif. En la arbolada plaza, los sombreados bancos presentan notable parroquia. Fuente visual: Familia Cuy‚îú√°s (cartotecadigital.icc.cat/)', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24329925710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24329925710.webp', 'https://www.flickr.com/photos/zaragozaantigua/24329925710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22004, 'Colegio Santa In‚îú¬Æs 1941', 'Dibujo del proyecto de nuevo edificio para el colegio de Santa In‚îú¬Æs, por Lorenzo Moncl‚îú‚ïës, agosto de 1941. Ser‚îú√≠ levantado en 1942, en el chafl‚îú√≠n entre las calles de Santa In‚îú¬Æs y Boggiero, sobre terrenos del convento de Santa In‚îú¬Æs. En 1949 fue ampliado y traspasado a las dominicas de la Anunciata. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36109225604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36109225604.webp', 'https://www.flickr.com/photos/zaragozaantigua/36109225604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23029, 'Calle del Conde de Aranda 1992', 'La calle del Conde de Aranda, tradicional salida hacia el oeste desde el centro de la ciudad, con sus 740 metros de longitud, vista desde las inmediaciones de la calle de Santa In‚îú¬Æs, a la izquierda, con el Coso Alto al fondo. Su configuraci‚îú‚îÇn cambi‚îú‚îÇ a‚îú‚ñíos despu‚îú¬Æs, en virtud de una remodelaci‚îú‚îÇn que, finalizada en 2004, incluy‚îú‚îÇ aceras m‚îú√≠s anchas y una medianera ajardinada con palmeras.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207027816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207027816.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207027816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23919, 'Tranv‚îú¬°a l‚îú¬°nea 5 1967', 'A‚îú‚ñío 1967. Tranv‚îú¬°a de la l‚îú¬°nea 5 (Venecia-Delicias), a su paso por la calle "General Franco". Detr‚îú√≠s del tranv‚îú¬°a, los restos de la manzana donde estuvo ubicada la antigua Casa de la Galera, como c‚îú√≠rcel correcional de mujeres durante los siglos XVII-XIX, que luego fue c‚îú√≠rcel masculina, y tambi‚îú¬Æn escuela de ni‚îú‚ñíos. Fuente visual: J. Ib‚îú√≠‚îú‚ñíez - Colecci‚îú‚îÇn Asociaci‚îú‚îÇn Filat‚îú¬Ælica Zaragozana "Gregorio Sierra".', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887018912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887018912.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887018912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23928, 'Calle Santa In‚îú¬Æs 1886', 'Vista de la calle de Santa In‚îú¬Æs de Zaragoza desde la iglesia del Portillo. A la derecha, calle del Portillo (hoy Conde de Aranda), flanqueada por la Casa de la Galera, reconvertida en colegio infantil en 1883. Abajo a la izquierda, huertas del convento de Santa In‚îú¬Æs. Al fondo, las torres de la ciudad: el Pilar, San Pablo, Santa Isabel, la Seo, la Torre Nueva...', 1886, 1886, 1886, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002883458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002883458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002883458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23940, 'Calle General Franco 1971', 'Vista de la calle del General Franco, esquina con la de Santa In‚îú¬Æs, en julio de 1971. A la derecha, los restos de la antigua Casa de la Galera, despu‚îú¬Æs colegio. Tras la valla con carteles comerciales, el colegio del Carmen y San Jos‚îú¬Æ de las Hijas de la Caridad de San Vicente de Pa‚îú‚ïël, en funcionamiento en ese lugar desde 1947, ocupando parte del terreno del convento de Santa In‚îú¬Æs. En el centro, unidad tranviaria n‚îú‚ïëmero 80 de la l‚îú¬°nea 5, "Venecia-Delicias", proveniente del barrio de las Delicias. Al fondo, edificios desaparecidos de la esquina de la avenida de Madrid con el paseo de Mar‚îú¬°a Agust‚îú¬°n. A la izquierda, vista parcial de la agencia urbana n‚îú‚ïëmero 1 de la Caja de Ahorros de Zaragoza y de la torre derecha de la iglesia del Portillo. Fuente visual: www.facebook.com/photo.php?fbid=1433912296624611&set=...', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65580400, -0.89130000, '0101000020E6100000F697DD938785ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30125233381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30125233381.webp', 'https://www.flickr.com/photos/zaragozaantigua/30125233381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24416, 'Convento de Santa In‚îú¬Æs 1930', 'Defectuosa pero interesante vista de 1930 del final de la calle de San Pablo, donde tambi‚îú¬Æn terminaba la de Santa In‚îú¬Æs. Al fondo, portada del convento de Santa In‚îú¬Æs, enclavado ah‚îú¬° desde el siglo XIV, y ocupado por monjas dominicas contemplativas. A partir de 1835, se dedicaron a la ense‚îú‚ñíanza. En 1942 se construy‚îú‚îÇ un edificio de nueva planta, en el chafl‚îú√≠n entre Santa In‚îú¬Æs y Boggiero. En 1949 se ampl‚îú¬°a y traspasa a las dominicas de la Anunciata. Fuente visual: Colecci‚îú‚îÇn Particular.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65684600, -0.89083800, '0101000020E6100000EC1681B1BE81ECBF14419C8713D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33500671741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33500671741.webp', 'https://www.flickr.com/photos/zaragozaantigua/33500671741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25827, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas P‚îú¬°as y termina en la de Santa In‚îú¬Æs. Imagen del tramo entre la calle de Santa In‚îú¬Æs hasta la de Mayoral. A la derecha, un pedazo de la antigua Casa de la Penitencia, habilitada en el siglo XVII en un edificio del siglo XV, derribada para construir la cosa que hoy hay.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65625600, -0.89075000, '0101000020E61000001B2FDD240681ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15071262611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15071262611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15071262611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25849, 'Calle de Santa In‚îú¬Æs 1951', 'Imagen capturada en la calle de Santa In‚îú¬Æs y centrada en el tramo entre la calle de Boggiero y la de San Pablo. A la izquierda, el moderno colegio de Santa In‚îú¬Æs, levantado en 1941 en una peque‚îú‚ñía parte del antiguo convento de Santa In‚îú¬Æs de las Madres Dominicas. A la derecha, original anchura de la calle definida por los antiguos inmuebles del n‚î¨‚ïë 164 de Boggiero, y del n‚î¨‚ïë 6, 8 y 10-12 de Santa In‚îú¬Æs. Al fondo, antiguo n‚î¨‚ïë 162 de la calle de San Pablo, donde la calle de Santa In‚îú¬Æs terminaba, desaparecido m‚îú√≠s tarde con motivo de la prolongaci‚îú‚îÇn de esa calle hasta la de Santa Luc‚îú¬°a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41306896562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41306896562.webp', 'https://www.flickr.com/photos/zaragozaantigua/41306896562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25850, 'Calle del General Franco c.1955', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 81 de la calle del General Franco, y centrada en el moderno colegio de Nuestra Se‚îú‚ñíora del Carmen y San Jos‚îú¬Æ, esquinero con la calle de Santa In‚îú¬Æs en primer t‚îú¬Ærmino y a la derecha. Casualmente y a su lado, transita una composici‚îú‚îÇn tranviaria M+R (posiblemente motor de la serie 60, y remolque de la 80) en servicio en la l‚îú¬°nea 5 "Venecia-Delicias", encaminada hacia la moderna plaza de Huesca, antigua de Rocasolano. Fuente visual: Ediciones DARVI, en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46246198735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46246198735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46246198735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20872, 'Dominguito y los barqueros 1250', 'Recuperaci‚îú‚îÇn del cad‚îú√≠ver de Santo Dominguito de Val. Museo de Huesca, siglo XVI. El ni‚îú‚ñío de siete a‚îú‚ñíos Dominguito de Val, infantico (monaguillo cantante) de La Seo, fue raptado por el jud‚îú¬°o Albayuceto, que lo entreg‚îú‚îÇ a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Como reza la pintura, "No es la primera ocasi‚îú‚îÇn que para hallar un infante se muestra el cielo radiante". Los caballeros de la barca son las autoridades que acudieron a dar fe. Esta leyenda fue creada en 1643, a imitaci‚îú‚îÇn de otras similares. A la izquierda, desembocadura del Huerva en el Ebro. Al fondo, puente de Tablas, puente de Piedra y Arrabal. Fuente: www.facebook.com/photo.php?fbid=10203933800178773&set...', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208940932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208940932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208940932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20877, 'Dominguito de Val 1250', 'Santo Dominguito de Val. Grabado de Mateo Gonz‚îú√≠lez, 1793. Museo de Zaragoza. Ni‚îú‚ñío legendario zaragozano del que se relataba su muerte violenta, situ‚îú√≠ndola en 1250, cuyo culto fue suprimido por el Concilio Vaticano II (1965). En el fondo de la imagen principal vemos una representaci‚îú‚îÇn del paso del r‚îú¬°o Ebro por Zaragoza. En el ‚îú√≠ngulo inferior derecho, el cad‚îú√≠ver mutilado luminoso en la desembocadura del r‚îú¬°o Huerva. A la izquierda, el Puente de Tablas y un embarcadero de dudosa verosimilitud.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19054241565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19054241565.webp', 'https://www.flickr.com/photos/zaragozaantigua/19054241565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22310, 'Parque Bruil c.1969', 'Imagen del "Parque Torre de Bruil" de Zaragoza, inaugurado en 1965. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15679984796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15679984796.webp', 'https://www.flickr.com/photos/zaragozaantigua/15679984796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22376, 'Vista a‚îú¬Ærea Ebro 1964', 'Vista a‚îú¬Ærea del r‚îú¬°o Ebro a su paso por Zaragoza, desde el este. En primer t‚îú¬Ærmino, la desembocadura del r‚îú¬°o Huerva, en la margen derecha. Fuente: Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65381700, -0.86519600, '0101000020E610000017299485AFAFEBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22129071029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22129071029.webp', 'https://www.flickr.com/photos/zaragozaantigua/22129071029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22446, 'Aloy Sala 1960', 'Imagen a‚îú¬Ærea capturada desde las alturas del este de la ciudad, centrada en el reciente Grupo Aloy Sala, construido en terrenos del arrabal de las Tener‚îú¬°as lindantes con el talud del r‚îú¬°o Huerva, que de izquierda a derecha, y en primer t‚îú¬Ærmino, desemboca en el Ebro; los campos de cultivos inmediatos a las traseras del militar Dep‚îú‚îÇsito de Sementales y los terrenos de la antigua Torre de Bruil (izquierda); y la f‚îú√≠brica de armamento Instalaza, en el indefinido espacio hasta el cauce del r‚îú¬°o Ebro (derecha). Este Grupo preve‚îú¬°a la construcci‚îú‚îÇn de 1579 viviendas, locales comerciales y servicios varios, incluyendo escuelas, ocio e iglesia cat‚îú‚îÇlica, como g‚îú¬Ænesis de un nuevo barrio completo destinado a la clase media, y en r‚îú¬Ægimen de alquiler, a realizar en varias fases, de las que s‚îú‚îÇlo se completaron las dos primeras. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65209000, -0.86674900, '0101000020E61000000CE71A6668BCEBBF3A0664AF77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31051119443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31051119443.webp', 'https://www.flickr.com/photos/zaragozaantigua/31051119443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23686, 'Aer‚îú‚îÇdromo Sanjurjo 1938', 'Imagen capturada en el aer‚îú‚îÇdromo Sanjurjo de Zaragoza con un contundente primer plano de bombas de 50 kg. apiladas y listas para cargarlas en los bombarderos operativos. Tras ellas y en la pista, un Junkers Ju-W 34 Hi, aparato de enlace, entrenamiento y servicio meteorol‚îú‚îÇgico, y varios Dornier Do-17 E.1, modernos bombarderos ligeros con capacidad de cargar 15 de estas bombas que los alemanes de la Legi‚îú‚îÇn C‚îú‚îÇndor denominaban "Fliegender Bleistift" (l‚îú√≠piz volador) por su alargado fuselaje, y que los nacionalistas espa‚îú‚ñíoles redenominaron m‚îú√≠s castizamente "Bacalao". Al fondo, l‚îú¬°nea de ‚îú√≠rboles que se‚îú‚ñíala el curso del Canal Imperial de Arag‚îú‚îÇn.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50301123318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50301123318.webp', 'https://www.flickr.com/photos/zaragozaantigua/50301123318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23057, 'Cuartel de Sementales 1994', 'Imagen capturada en el solar dejado tras el derribo de las instalaciones del cuartel 5‚î¨‚ïë Dep‚îú‚îÇsito de Sementales sito en la calle del Asalto, entre el parque de Bruil y el Grupo de Viviendas Aloy Sala. Esta dependencia militar no fue incluida en la Operaci‚îú‚îÇn Cuarteles a pesar de las gestiones del Ayuntamiento al principio de los a‚îú‚ñíos 80 por las reclamaciones realizadas por el ramo de la Guerra, tanto econ‚îú‚îÇmicas como que all‚îú¬° se levantaran viviendas militares. En paralelo, el vecindario del barrio de las Tener‚îú¬°as promovi‚îú‚îÇ gestiones para solicitar el traslado de este cuartel por sus afecciones insalubres, nocivas y molestas. Finalmente, en 1994 se lleg‚îú‚îÇ a un acuerdo y el cuartel fue desmantelado y trasladado a unas nuevas instalaciones en Garrapinillos. El solar resultante ser‚îú¬°a objeto de un Plan Especial del ‚îú√ºrea de Intervenci‚îú‚îÇn U-7-2 aprobado en 1996 del que resultar‚îú¬°a la urbanizaci‚îú‚îÇn actual de este espacio. En la escena, vista del solar dejado tras el derribo del cuartel, con el parque de Bruil al fondo, sobre el que emergen los bloques de la calle de Alvira Lasierra. A la derecha, viviendas de la calle del Asalto esquineras con la calle de Cant‚îú¬°n y Gamboa y vecinas del convento de las madres agustinas de Santa M‚îú‚îÇnica. M‚îú√≠s a la derecha, se destaca la torre del antiguo convento de San Agust‚îú¬°n.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65102200, -0.86845600, '0101000020E6100000AF7AC03C64CAEBBFFE7C5BB054D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449979087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449979087.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449979087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23201, 'Calle Vicente L‚îú‚îÇpez Abad‚îú¬°a 2010', 'Foto: Oliver Duch. Solar entre las calles de Vicente L‚îú‚îÇpez Abad‚îú¬°a (al fondo) y Pascual Albero Burillo, junto al parque Bruil. All‚îú¬° se construy‚îú‚îÇ en 2010 la Escuela Infantil Municipal Parque Bruil, inaugurada en octubre de 2012 con domicilio en la calle Vicente L‚îú‚îÇpez Abad‚îú¬°a 4. En su subsuelo est‚îú√≠ previsto un aparcamiento subterr‚îú√≠neo. Fuente: Heraldo de Arag‚îú‚îÇn.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65156300, -0.86685900, '0101000020E6100000D2C8E7154FBDEBBF4F24986A66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32518208074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32518208074.webp', 'https://www.flickr.com/photos/zaragozaantigua/32518208074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24706, 'Prolongaci‚îú‚îÇn Echegaray 1989', 'Vista a‚îú¬Ærea de las obras de 1989 en el entorno de la desembocadura del r‚îú¬°o Huerva, en lo que ser‚îú√≠ la prolongaci‚îú‚îÇn del paseo de Echegaray y Caballero. En primer t‚îú¬Ærmino, construcci‚îú‚îÇn del puente de La Uni‚îú‚îÇn. En el centro, puente sobre el Huerva. Al fondo a la derecha, puentes del Pilar, de Piedra y de Santiago. Fuente: www.eszaragoza.eu/2017/06/lo-que-sucedia-en-zaragoza-dura...', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65240600, -0.86526100, '0101000020E6100000DD2230D637B0EBBF6ADB300A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36403250961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36403250961.webp', 'https://www.flickr.com/photos/zaragozaantigua/36403250961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24736, 'El Huerva llega al Ebro 1977', 'Imagen de la desembocadura del Huerva en el Ebro. Pocos cambios en este entorno desde que el Huerva abandonara, hace ya bastante tiempo, su antiguo cauce, por la actual calle del Asalto, y se desviara hacia la derecha, hacia tierras m‚îú√≠s bajas, dejando el meandro del actual Parque Bruil como un lugar muy favorable para la agricultura. En la margen izquierda, panorama de las diferentes urbanizaciones, en este caso con grandes bloques habitacionales que iban surgiendo desde mediados de los a‚îú‚ñíos 70. En primer t‚îú¬Ærmino, sobresaliendo detr‚îú√≠s de naves y almacenes, la urbanizaci‚îú‚îÇn Vadorrey. A la izquierda, m‚îú√≠s al fondo, la urbanizaci‚îú‚îÇn denominada "El Colector", actual Manuel Viola. El alto bloque que sobresale por encima de todos, es el edificio "La Estrella", de 14 alturas, junto a la Avenida de Catalu‚îú‚ñía. Fuente visual: "La evoluci‚îú‚îÇn urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65295400, -0.86484000, '0101000020E610000078B988EFC4ACEBBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15139541264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15139541264.webp', 'https://www.flickr.com/photos/zaragozaantigua/15139541264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24961, 'Al norte del Parque Bruil 1974', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Noviembre 1974. La Torre de Bruil-Parque Bruil, el Dep‚îú‚îÇsito de Sementales del Ej‚îú¬Ærcito de Tierra, el Grupo de Viviendas "Aloy Sala" (Arrabal de las Tener‚îú¬°as), y el r‚îú¬°o Huerva ya casi desembocando en el Ebro, delimitaban una interesante y poco visitada zona de antiguos campos de cultivo, a escasos minutos del centro de la ciudad. Dos principales caminos de servicio de fincas hac‚îú¬°an las funciones de irregular cardo y decumano para un llano per‚îú¬°metro donde cereales y herb‚îú√≠ceas se suced‚îú¬°an seg‚îú‚ïën el a‚îú‚ñío. Un riego derivado de acequia, y un desag‚îú‚ïùe de viejos lavaderos, vert‚îú¬°an aguas a la trinchera del Huerva (a la izquierda). El desarrollo urbano de la ciudad hab‚îú¬°a sido orientado hacia otras latitudes, y el entorno no se consideraba de la suficiente calidad como para esperar una revalorizaci‚îú‚îÇn suficiente y r‚îú√≠pida del precio del suelo agr‚îú¬°cola. Pese a tener de vecino al nov‚îú¬°simo y espectacular Parque Bruil, la inmediatez del cuartel del Ej‚îú¬Ærcito (caballer‚îú¬°a), las viviendas baratas de los 50, y que las Tener‚îú¬°as no era precisamente el Soho zaragozano, mantuvo en barbecho espectante esta zona durante alguna d‚îú¬Æcada m‚îú√≠s. Ahora esto es otra cosa, distinta. En la imagen, vista de los campos de cultivo desde la actual calle Alto Arag‚îú‚îÇn. De izquierda a derecha, el r‚îú¬°o Huerva, el reciente edificio H‚îú√≠bitat Don 2000 (1973), y tras el muro de delimitaci‚îú‚îÇn, los ‚îú√≠rboles y fronda del Parque Bruil, y las arom‚îú√≠ticas instalaciones del cuartel de caballer‚îú¬°a. Justo detr‚îú√≠s, las ruinas del antiguo convento de S. Agust‚îú¬°n y su caracter‚îú¬°stica y desmochada torre, y la confluencia viaria de Alonso V con la calle Asalto.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65139800, -0.86796800, '0101000020E6100000552FBFD364C6EBBF0457790261D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849195251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849195251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849195251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24963, 'Parque Bruil 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1965. Tras m‚îú√≠s de diez a‚îú‚ñíos de gestiones, inauguraci‚îú‚îÇn del municipal Parque Bruil, entre el r‚îú¬°o Huerva (este), la calle Asalto (oeste), el cuartel de Sementales y unos campos de cultivos (norte), y un vial que poco despu‚îú¬Æs se denominar‚îú√≠ Mariano Alvira Lasierra.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850897742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850897742.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850897742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24974, 'Parque Bruil 1970', 'Piscinas del parque Bruil de Zaragoza. Postal, ed. Zerkowitz, serie 82, n‚î¨‚ïë 1.074, 1970. Fuente: www.todocoleccion.net', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19585124351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19585124351.webp', 'https://www.flickr.com/photos/zaragozaantigua/19585124351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25421, 'R‚îú¬°o Ebro y murallas s.XVII', 'Trascoro de la Seo de Zaragoza. Siglo XVII. Relieve de la vista del r‚îú¬°o Ebro y las murallas de Zaragoza con la puerta del ‚îú√ºngel junto al puente de Piedra, y el puente de Tablas en primer t‚îú¬Ærmino. Escena de la leyenda del hallazgo del los restos de Santo Dominguito de Val decapitado. Fuente: Cat‚îú√≠logo El municipio en Arag‚îú‚îÇn, DPZ, 2004.', NULL, NULL, NULL, NULL, 'CASCO HIST‚îú√¥RICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18672417202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18672417202.webp', 'https://www.flickr.com/photos/zaragozaantigua/18672417202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25536, 'Colector del Huerva 1934', 'El emisario del alcantarillado al r‚îú¬°o Ebro en la margen izquierda de la desembocadura del Huerva fue construido en 1907 y ampliado en 1934, momento que recoge la foto. Entre los trabajadores, algunas bestias de carga. Hasta la urbanizaci‚îú‚îÇn reciente de la zona en el siglo XXI, el colector vert‚îú¬°a las aguas residuales al descubierto, dejando un olor caracter‚îú¬°stico. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65312700, -0.86547500, '0101000020E6100000E02D90A0F8B1EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18701889484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18701889484.webp', 'https://www.flickr.com/photos/zaragozaantigua/18701889484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23059, 'Vuelta ciclista a Espa‚îú‚ñía 1990', 'El 13 de mayo de 1990 se celebr‚îú‚îÇ la etapa 19 de la Vuelta ciclista a Espa‚îú‚ñía, con un recorrido de 30 km contrarreloj dentro de la ciudad de Zaragoza. El ganador de la prueba fue Peio Ruiz Cabestany, y el de la Vuelta, Marco GIovannetti. La imagen est‚îú√≠ extra‚îú¬°da del v‚îú¬°deo de la retransmisi‚îú‚îÇn en TVE, y muestra al ciclista Pedro Delgado atravesando el puente de la Uni‚îú‚îÇn o de Las Fuentes sobre el Ebro, con el Pilar al fondo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65246900, -0.86273700, '0101000020E6100000A79201A08A9BEBBFB153AC1A84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494089228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494089228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494089228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21222, 'R‚îú¬°o Ebro c.1905', 'Photoglob Z‚îú‚ïùrich. Ca.1905. "R‚îú¬°o Ebro y Nuestra Se‚îú‚ñíora del Pilar". Imagen del Ebro, con el fluvial paso en barca, por a‚îú¬Æreo camino de sirga, del "T‚îú¬°o Toni". Al fondo, el puente de las piedras, con sus pretiles y sus leones. Detr‚îú√≠s, el de hierros. Fuente: www.el-trastero.eu/caddie/images/zaragoza-0010.webp', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15934073422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15934073422.webp', 'https://www.flickr.com/photos/zaragozaantigua/15934073422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21442, 'R‚îú¬°o Ebro c.1910', 'Imagen capturada junto a la ribera del r‚îú¬°o Ebro inmediata a la arboleda de Macanaz, en la margen izquierda, y centrada en una vista que incluye al Puente de Piedra y el Puente de Hierro m‚îú√≠s al fondo, y el templo del Pilar con las dos torres recayentes a la hom‚îú‚îÇnima plaza. En primer t‚îú¬Ærmino, embarcadero del paso de barcas que d‚îú¬Æcadas m‚îú√≠s tarde se‚îú‚ñíalar‚îú¬°a la ubicaci‚îú‚îÇn de una pasarela peatonal permanente. Sobre el Puente de Piedra transita un coche posiblemente de la tranviaria l‚îú¬°nea del Arrabal. A la derecha, entre el Pilar y la ribera de la margen derecha, el recoleto espacio junto a la Puerta del Fin y la Escuela Normal de Maestras utilizado como ferial de ganado.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65886900, -0.88098700, '0101000020E6100000D66F26A60B31ECBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49334482061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49334482061.webp', 'https://www.flickr.com/photos/zaragozaantigua/49334482061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21502, 'Almadieros 1923', 'Miguel Faci Abad. 1923. "Zaragoza. Ba‚îú‚ñíos del Ebro y navatas." En la imagen, tomada desde la margen izquierda del r‚îú¬°o Ebro, aspecto de la arboleda de Macanaz cuando a‚îú‚ïën era utilizada para desembarcar los maderos que los almadieros del Valle del Roncal tra‚îú¬°an a la ciudad. Los maderos, una vez sacados del agua, se dejaban "en cuarentena", para que se secaran completamente antes de su uso, o distribuci‚îú‚îÇn. Mientras los almadieros descansan al sol de la tarde, unos chavales en pelota picada se remojan para refrescarse, mientras otros, vestidos, se van a remojar sin pretenderlo. El uso del Ebro como fluvial ruta de transporte de madera fue posible hasta la puesta en funcionamiento de la presa de Yesa (1959-1960). Fuente visual: "Miguel y Gabriel Faci. Fot‚îú‚îÇgrafos fundadores de la Real Sociedad Fotogr‚îú√≠fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci‚îú‚îÇn Provincial de Zaragoza, 1999.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15516887172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15516887172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15516887172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21685, 'El paso del Ebro 1939', 'Albert Louis Deschamps. Cruzando el Ebro a mano, a la altura de San Juan de los Panetes y la Zuda, una maniobra de la Barca del T‚îú¬°o Toni, al precio de cinco c‚îú¬Æntimos de peseta la persona. El Torre‚îú‚îÇn de la Zuda se encontraba entre diversas viviendas que se le hab‚îú¬°an ido adosando a lo largo del tiempo. En 1931 comenzar‚îú√≠ una intervenci‚îú‚îÇn en la zona, con la ampliaci‚îú‚îÇn de la avenida de Nuestra Se‚îú‚ñíora del Pilar, las murallas romanas, el torre‚îú‚îÇn de la Zuda y la iglesia de San Juan de los Panetes. Luego vendr‚îú√≠ la idea de la V‚îú¬°a Imperial, y luego la de C‚îú¬Æsar Augusto... En la imagen a‚îú‚ïën no estaba construida la Pasarela Peatonal sobre el Ebro, que se iniciar‚îú√≠ en 1940, y se inaugurar‚îú√≠ en 1941.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65835600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903094946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903094946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903094946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21734, 'El Ebro y el Pilar a‚îú‚ñíos 30', 'Foto: Miguel Mar‚îú¬°n Chivite. Panorama del r‚îú¬°o Ebro con el Pilar al fondo. A la izquierda, puente de piedra y ni‚îú‚ñío bebiendo. La embarcaci‚îú‚îÇn que aparece es un modelo motorizado que efect‚îú‚ïëa el recorrido tradicional de la barca del T‚îú¬°o Toni, que seguir‚îú√≠ prestando sus servicios mediante sirga a mano hasta la construcci‚îú‚îÇn de la pasarela peatonal en los a‚îú‚ñíos 40. Fuente: Archivo Heraldo de Arag‚îú‚îÇn.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351091648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351091648.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351091648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21773, 'R‚îú¬°o Ebro 1932', 'R‚îú¬°o Ebro. Al fondo, el puente del Ferrocarril. A la derecha, la arboleda de Macanaz, la Caseta de Ba‚îú‚ñíos, y la √î√á¬£Sociedad Naturista Helios√î√á√ò. Una barca cruza el r‚îú¬°o. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65854900, -0.88066500, '0101000020E61000003C6BB75D682EECBF21E868554BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855738617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855738617.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855738617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21829, 'Embarcadero 1933', 'Embarcadero en el r‚îú¬°o Ebro. Al fondo, el Pilar. Fuente: Heraldo de Arag‚îú‚îÇn.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65897000, -0.88242700, '0101000020E6100000C16F438CD73CECBFC685032159D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935400752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935400752.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935400752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21842, 'Pasarela de Macanaz 1933', 'Dibujo representando la pasarela peatonal sobre el r‚îú¬°o Ebro proyectada por el ingeniero Luis de Fuentes L‚îú‚îÇpez como forma de conectar la calle de Antonio P‚îú¬Ærez con la arboleda de Macanaz. El antropol‚îú‚îÇgico y ‚îú‚ïënico paso de sirga del t‚îú¬°o Toni ya hab‚îú¬°a dado paso a la introducci‚îú‚îÇn por ‚îú√ºngel Bag‚îú‚ïù‚îú¬Æs de las modernas barcas a gasolina que cubr‚îú¬°an el tr‚îú√≠nsito de personas entre las dos orillas mediante varios embarcaderos. Tras los diversos procesos de embellecimiento de ambas riberas del Ebro, ahora parec‚îú¬°a tocarle el turno a la construcci‚îú‚îÇn de un paso peatonal estable de orilla a orilla, si bien la idea finalmente ser‚îú¬°a materializada al principio de la siguiente d‚îú¬Æcada, tan cercana, y tan diferente. En el dibujo, la proyectada pasarela representada entre la orilla derecha (a la izquierda) con el final de la calle de Antonio P‚îú¬Ærez, y la orilla izquierda (a la derecha) con la arboleda de Macanaz y su acceso casi cinco metros m‚îú√≠s bajo a salvar mediante escaleras. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65843900, -0.88113600, '0101000020E61000001381EA1F4432ECBF9AB4A9BA47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35569416784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35569416784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35569416784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21844, 'Calle de Demetrio Gal‚îú√≠n 1934', 'Imagen capturada en la despejada calle de Demetrio Gal‚îú√≠n, paralela a la arboleda de Macanaz, y centrada en la f‚îú√≠brica de lavaje y apartado de lanas de Jaime Corcoy, que inici‚îú‚îÇ su actividad en 1917 como Manufactura de Lanas de Mor‚îú‚îÇn y An‚îú‚îÇs, con dise‚îú‚ñío de Miguel ‚îú√ºngel Navarro, en el entonces camino de Ranillas. De esta instalaci‚îú‚îÇn perdura la chimenea, en un entorno descontextualizado, bastante diferente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.66064300, -0.88270300, '0101000020E61000004698A25C1A3FECBF69AA27F38FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35653992904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35653992904.webp', 'https://www.flickr.com/photos/zaragozaantigua/35653992904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22037, 'R‚îú¬°o Ebro c.1942', 'Acuarela del prol‚îú¬°fico dibujante, poeta y periodista Ambrosio Ruste Alonso (1871-1955) titulada "El Pilar" porque este templo centra desde el fondo de la escena una fluvial vista capturada desde un embarcadero recreativo en la arboleda de Macanaz. Apenas esbozada, la pasarela del Ebro aparece levemente tendida sobre el r‚îú¬°o. Fue proyectada en 1933 por el ingeniero Luis de Fuentes L‚îú‚îÇpez como forma de conectar la calle de Antonio P‚îú¬Ærez con la arboleda de Macanaz, si bien su construcci‚îú‚îÇn se demor‚îú‚îÇ en el tiempo para ser finalmente bendecida e inaugurada el 25 de febrero de 1941, terminando as‚îú¬° con la tradicional barca de sirga que desde el siglo XIX conectaba las dos riberas y que desde los a‚îú‚ñíos 30 fue sustituida por "gasolineras" o barcazas a motor. Como siempre, una mejora en esta ciudad que conlleva un derribo o una desaparici‚îú‚îÇn de un elemento previo fue ardorosamente aplaudida en la prensa de la ‚îú¬Æpoca, donde se sentenci‚îú‚îÇ que la referida barca era "vieja", "antiest‚îú¬Ætica" y "lenta", mientras que la nueva pasarela era "m‚îú√≠s l‚îú‚îÇgica, c‚îú‚îÇmoda y eficaz". As‚îú¬° las cosas y de forma no menos l‚îú‚îÇgica, esta situaci‚îú‚îÇn se repetir‚îú¬°a casi un cuarto de siglo despu‚îú¬Æs, cuando esta pasarela fue desmontada para dar paso a un nuevo puente m‚îú√≠s c‚îú‚îÇmodo y eficaz.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65914200, -0.88259600, '0101000020E6100000C59272F7393EECBFC4B5DAC35ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54754018338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54754018338.webp', 'https://www.flickr.com/photos/zaragozaantigua/54754018338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22082, 'Pasarela sobre el Ebro a‚îú‚ñíos 50', 'Magn‚îú¬°fica imagen del acceso desde la Arboleda de Macanaz a la pasarela sobre el r‚îú¬°o Ebro construida en 1941, que desapareci‚îú‚îÇ para dar paso al puente de Santiago en 1967. Al fondo, la iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=643306315778704&set=p...', 1950, 1950, 1959, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15783586076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15783586076.webp', 'https://www.flickr.com/photos/zaragozaantigua/15783586076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22095, 'Pasarela 1955', '"Saliendo de la escuela", foto de Jos‚îú¬Æ Antonio Duce, 1955. Ni‚îú‚ñíos sobre la pasarela peatonal del Ebro que ser‚îú√≠ sustituida por el puente de Santiago. Al fondo, San Juan de los Panetes. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20090004454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20090004454.webp', 'https://www.flickr.com/photos/zaragozaantigua/20090004454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22230, 'Helios c.1959', 'Imagen capturada desde el campin de Helios y orientada hacia el este, con vista parcial de la original piscina y la pista de baloncesto. Hacia el fondo, la arboleda de Macanaz, flanqueada por viviendas del Arrabal a la izquierda, y el templo del Pilar a la derecha.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.66000800, -0.88296100, '0101000020E61000003197546D3741ECBF978C63247BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49911991977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49911991977.webp', 'https://www.flickr.com/photos/zaragozaantigua/49911991977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22289, 'Puente de Santiago 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1965. "Crecida del r‚îú¬°o Ebro." 1965 fue otro a‚îú‚ñío de crecida destacable del r‚îú¬°o Ebro. A su paso por la ciudad, la altura del agua fluyendo alcanz‚îú‚îÇ los cinco metros de altura. En la imagen, aspecto del puente de Santiago en construcci‚îú‚îÇn, mientras el cauce se hinchaba y desbordaba all‚îú¬° donde las riberas lo permit‚îú¬°an, como en la zona de Helios.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208136758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208136758.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208136758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22313, 'Pasarela Ebro 1962', 'Jos‚îú¬Æ Antonio Duce. 1962. Imagen de la Pasarela Peatonal del Ebro. Captura de imagen desde la Margen Izquierda. En la ribera derecha, marcado contraluz para la fachada de edificios al paseo del Ebro. Entre las sombras, el dieciochesco antiguo Almac‚îú¬Æn de la Sal, junto a algunas otras edificaciones que siglo de las Luces, que a‚îú‚ñíos despu‚îú¬Æs terminar‚îú¬°an cayendo derrumbados por piquetas y mec‚îú√≠nicos ingenios. Fuente visual: www.gozazaragoza.com/contenido.php?id=9799', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747149020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747149020.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747149020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22356, 'El Pilar a‚îú‚ñíos 60', 'Foto: Colecci‚îú‚îÇn Adolfo Mart‚îú¬°nez. Pirag‚îú‚ïùistas en el r‚îú¬°o Ebro, con el Pilar al fondo. Fuente: rafaelcastillejo.com', 1960, 1960, 1969, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20712101535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20712101535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20712101535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22357, 'Puente Santiago 1964', 'Foto: Emilio Gil. Construcci‚îú‚îÇn del Puente de Santiago de Zaragoza, con los restos de la estructura de la pasarela en primer plano y la Margen Izquierda al fondo. Fuente: rafaelcastillejo.com', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20715635991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20715635991.webp', 'https://www.flickr.com/photos/zaragozaantigua/20715635991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22364, 'Esqu‚îú¬° acu‚îú√≠tico c.1969', 'Postal, finales de los a‚îú‚ñíos 60. Vista del puente de Santiago sobre el r‚îú¬°o Ebro en Zaragoza, con baturros en primer plano y una lancha practicando esqu‚îú¬° acu‚îú√≠tico, deporte que no ha llegado a cuajar entre los tradicionales aragoneses. Fuente: www.facebook.com/photo.php?fbid=10201037600339410&set...', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268207276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268207276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268207276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22431, 'Vista a‚îú¬Ærea 1966', 'Canicular vista a‚îú¬Ærea centrada en la construcci‚îú‚îÇn del nuevo puente sobre el r‚îú¬°o Ebro y la apertura en la margen izquierda de la avenida de los Pirineos como inicio de la moderna carretera hacia Huesca. En la margen derecha, aun con los derribos de viviendas de la antigua calle de Antonio P‚îú¬Ærez (moderna V‚îú¬°a Imperial y luego avenida de C‚îú¬Æsar Augusto), el tr‚îú√≠nsito rodado se habr‚îú¬°a de topar, indefectiblemente, con el Mercado Central (en primer t‚îú¬Ærmino), construido en los albores del siglo cuando ninguna mente con visi‚îú‚îÇn de futuro pudo siquiera so‚îú‚ñíar que las necesidades de movilidad de un gran parque autom‚îú‚îÇvil habr‚îú¬°an de requerir practicar cirug‚îú¬°a urban‚îú¬°stica radical en el casco antiguo de la ciudad. No pasar‚îú¬°an muchos a‚îú‚ñíos hasta que se fomentara la bochornosa campa‚îú‚ñía que exig‚îú¬°a derribar el Mercado Central para dar paso a la modernidad identificada con la hegemon‚îú¬°a del veh‚îú¬°culo privado, y la adecuaci‚îú‚îÇn viaria a sus exponenciales necesidades de espacio. Fuente: TAF Helic‚îú‚ñìpters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65858700, -0.88163100, '0101000020E61000000C7904375236ECBF0E492D944CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29290884717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29290884717.webp', 'https://www.flickr.com/photos/zaragozaantigua/29290884717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22434, 'Puente de Santiago 1966', 'Imagen capturada durante la construcci‚îú‚îÇn del "Nuevo puente sobre el r‚îú¬°o Ebro" por el M.O.P., con interesante vista en la margen izquierda del barrio de la Hortilla (antes de perder la "h") y aun del de Ranillas, el ribere‚îú‚ñío camping de Helios, el antiguo edificio de los "Ba‚îú‚ñíos del Ebro" y, sobresaliendo entre la foresta, la chimenea de la antigua "Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs", en el Camino de Ranillas. Al fondo, a la izquierda, el puente del ferrocarril. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30235519295.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30235519295.webp', 'https://www.flickr.com/photos/zaragozaantigua/30235519295/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22451, 'Puente de Santiago 1966', 'Imagen, capturada desde la margen izquierda, durante la construcci‚îú‚îÇn del nuevo puente sobre el r‚îú¬°o Ebro que sustituy‚îú‚îÇ a la pasarela peatonal. A la izquierda, vista parcial de la obra de la piscina cubierta del Club Nataci‚îú‚îÇn Helios, ubicada donde estuviera el antiguo edificio de los Ba‚îú‚ñíos del Ebro. Una interesante crecida del r‚îú¬°o pone a prueba las obras, aunque no tiene la descomunal categor‚îú¬°a de las de 1643, o 1871, entre otras cosas, por las obras de regulaci‚îú‚îÇn en cabecera de cuenca. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31407744436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31407744436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31407744436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22488, 'Puente de Santiago 1966', 'Veraniega vista panor‚îú√≠mica capturada en altura y centrada en la construcci‚îú‚îÇn del nuevo puente sobre el r‚îú¬°o Ebro que, denominado de Santiago, supuso el desmontaje de la previa pasarela peatonal de pago, la apertura para el tr‚îú√≠fico rodado en la margen izquierda de la gran avenida de los Pirineos como inicio de la moderna carretera hacia Huesca, y en la margen derecha la consolidaci‚îú‚îÇn de la avenida de C‚îú¬Æsar Augusto como v‚îú¬°a de alta capacidad que habr‚îú¬°a de conducir el tr‚îú√≠fico, tras despejar el camino por una parte de la antigua ciudad, hasta la misma puerta del Carmen. En primer t‚îú¬Ærmino, la arbolada zona oriental de la gran plaza del Pilar determinada por el referencial monumento "A los h‚îú¬Æroes y m‚îú√≠rtires de Zaragoza ca‚îú¬°dos en nuestra Gloriosa Cruzada de Liberaci‚îú‚îÇn 1936-1939", la iglesia de San Juan de los Panetes y el torre‚îú‚îÇn de la Zuda. En la margen izquierda, la arboleda de Macanaz, el Club Nataci‚îú‚îÇn Helios en proceso de ampliaci‚îú‚îÇn de instalaciones, la antigua factoria "Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs", el barrio de la Ortilla y el tendido del enlace ferroviario hacia Alsasua. Fuente: TAF Helic‚îú‚ñìpters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44125666581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44125666581.webp', 'https://www.flickr.com/photos/zaragozaantigua/44125666581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22569, 'Vista del Ebro c.1977', 'Postal. Vista a‚îú¬Ærea del r‚îú¬°o Ebro cruzado por el puente de Santiago, desde la margen izquierda. La masa frondosa dividida por el Segundo Cintur‚îú‚îÇn es la Arboleda de Macanaz. A la derecha, el Club Nataci‚îú‚îÇn Helios, con su piscina cubierta construida en 1976. Al fondo, la vieja ciudad, con el Pilar como referencia vertical. Fuente visual: www.delcampe.net/', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65910000, -0.88142000, '0101000020E61000004D4A41B79734ECBF956588635DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295952888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295952888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295952888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22918, 'Baturros y Pilar a‚îú‚ñíos 80', 'Pareja de baturros con el Pilar al fondo. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65910700, -0.87989500, '0101000020E6100000D53E1D8F1928ECBF47C8409E5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422065605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422065605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422065605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22956, 'Av. de los Pirineos 1981', 'Imagen capturada durante la salida desde Zaragoza de la antorcha que anunciaba la celebraci‚îú‚îÇn de la Universiada de Invierno en el Pirineo Aragon‚îú¬Æs, en instalaciones de Formigal, Candanch‚îú‚ïë, Ast‚îú‚ïën, Panticosa, y Jaca, donde se celebrar‚îú¬°an entre otros actos las ceremonias de apertura, el d‚îú¬°a 24 de febrero, y la de clausura, el 4 de marzo. El fallido Golpe de Estado del 23 de febrero estuvo a punto de hacer que se suspendiera este evento deportivo, que finalmente tuvo lugar las fechas previstas con m‚îú√≠s que notable presencia de Polic‚îú¬°a, Guardia Civil, y Ej‚îú¬Ærcito. Este "Circo Blanco" fue el pistoletazo de salida de la carrera en pos del sue‚îú‚ñío, o pesadilla, de organizar una Olimpiada de Invierno en la Jacetania, que se prolongar‚îú√≠ en el tiempo. Al fondo de la imagen, arboleda de Macanaz y el templo metropolitano del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.66020700, -0.88126600, '0101000020E61000009F7422C15433ECBF8ECBB8A981D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48641710017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48641710017.webp', 'https://www.flickr.com/photos/zaragozaantigua/48641710017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23818, 'Paseo del Ebro 1927', 'Marcelino Secorum, 1927. Dibujo del anteproyecto (no realizado) de embellecimiento del paseo del Ebro. Perspectiva de conjunto. Fuente: Archivo Municipal de Zaragoza.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65837200, -0.88201700, '0101000020E6100000568330B77B39ECBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18650377766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18650377766.webp', 'https://www.flickr.com/photos/zaragozaantigua/18650377766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23826, 'El Pilar c.1864', 'Vista del Pilar desde la Margen Izquierda. Fuente visual: original de Ferrier et Soulier editada por J. L‚îú¬Ævy & C‚îú¬°a, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, edici‚îú‚îÇn 1895. ("Espa‚îú‚ñía", viaje durante el reinado de Amadeo I de Saboya).', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65864200, -0.88221200, '0101000020E6100000A87004A9143BECBFD2E28C614ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20725320782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20725320782.webp', 'https://www.flickr.com/photos/zaragozaantigua/20725320782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24355, 'Barca y pasarela 1940', 'Construcci‚îú‚îÇn de la pasarela sobre el Ebro a la altura de San Juan de los Panetes, que estar‚îú√≠ en servicio hasta la inauguraci‚îú‚îÇn del puente de Santiago, en 1967. Mientras van acab‚îú√≠ndola, la c‚îú¬Ælebre barca del T‚îú¬°o Toni contin‚îú‚ïëa llevando de orilla a orilla a la gente, con su sirga. En 1935 el MOPU hab‚îú¬°a otorgado una concesi‚îú‚îÇn para la construcci‚îú‚îÇn de una pasarela que comunica ambas orillas del Ebro. Se construy‚îú‚îÇ en 1940, y se abri‚îú‚îÇ al servicio p‚îú‚ïëblico en 1941. El proyecto fue del ingeniero Luis Fuentes L‚îú‚îÇpez. La construcci‚îú‚îÇn y montaje de la parte met‚îú√≠lica de la pasarela se hizo por "Maquinista y Fundiciones del Ebro, S.A." Dirigi‚îú‚îÇ la obra de f‚îú√≠brica complementaria Enrique Bressel. Funcionaba la pasarela d‚îú¬°a y noche.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65832400, -0.88150600, '0101000020E6100000F14927124C35ECBF0116F9F543D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934310221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934310221.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934310221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24675, 'Puente Santiago c.1979', 'Un hombre pasea una mula por el puente de Santiago de Zaragoza. Al fondo, la Cruz de los Ca‚îú¬°dos, San Juan de los Panetes, el torre‚îú‚îÇn de la Zuda y el Mercado Central. Fuente: www.facebook.com/photo.php?fbid=1578563142386483&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20723475792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20723475792.webp', 'https://www.flickr.com/photos/zaragozaantigua/20723475792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24681, 'R‚îú¬°o Ebro 1872', '"R‚îú¬°o Ebro y San Juan de los Panetes", ‚îú‚îÇleo sobre tabla, Francisco Pradilla, 1872. Vista del r‚îú¬°o Ebro desde la arboleda de Macanaz, con la silueta de San Juan de los Panetes al fondo. Fuente: Zaragoza vista por los artistas, 1908-2008.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32234419582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32234419582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32234419582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24738, 'Puente de Santiago 1967', '"Gente en el reci‚îú¬Æn inaugurado Puente de Santiago." Aun la gente ind‚îú¬°gena, tres semanas despu‚îú¬Æs de su oficial inauguraci‚îú‚îÇn, y hasta la normalizaci‚îú‚îÇn del tr‚îú√≠fico rodado a motor de explosi‚îú‚îÇn (ese era el principal horizonte funcional del puente), se quedaba en medio un ratico "a ver si el puente aguanta". Otros, m‚îú√≠s prudentes, observaban la riesgosa probanza desde la ribera. En la margen izquierda, imagen del barrio de la Hortilla, antes de perder la "h", del camping de Helios y, sobresaliendo de los ‚îú√≠rboles, de la chimenea de la antigua Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs, en el Camino de Ranillas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181013490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181013490.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181013490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24739, 'Ba‚îú‚ñíos p‚îú‚ïëblicos 1930', 'Foto colecci‚îú‚îÇn Luis Rasal, 1930. Edificio de los ba‚îú‚ñíos p‚îú‚ïëblicos de Zaragoza a orillas del Ebro (durante la riada de 1930). Situado en la actual ubicaci‚îú‚îÇn del Club Nataci‚îú‚îÇn Helios, en la margen izquierda. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=820302567992370&set=o...', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65915600, -0.88227400, '0101000020E61000002A8E03AF963BECBF297B4B395FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259142238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259142238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259142238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24782, 'Camino de Ranillas 1977', 'Imagen del pluricentenario camino de Ranillas, tras el cruce de la reciente avenida de los Pirineos abierta para tr‚îú√≠fico rodado. A la izquierda, prolongaci‚îú‚îÇn de la densa arboleda de Macanaz, y muros perimetrales de las instalaciones del C.N. Helios. A la derecha, el barrio de la Ortilla. Al fondo, la huerta y soto de Ranillas. El camino de Ranillas aparece muy despejado tras el derribo de las antiguas "Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs", de las que s‚îú‚îÇlo se dej‚îú‚îÇ en pie su estilita chimenea, ya fuera de plano, hacia la derecha, como la recientemente clausurada y desmantelada l‚îú¬°nea del ferrocarril de los Enlaces. El crecimiento urban‚îú¬°stico de la Margen Izquierda, desde la construcci‚îú‚îÇn del puente de Santiago y la apertura de la avenida de los Pirineos, en progresi‚îú‚îÇn geom‚îú¬Ætrica y en unos pocos a‚îú‚ñíos transform‚îú‚îÇ, de forma radical, toda esta parte de la periferia rururbana de la ciudad, hasta dejarla irreconocible. Una supuesta "actuaci‚îú‚îÇn urgente" urban‚îú¬°stica supuso la desaparici‚îú‚îÇn de los barrios de la Ortilla, y de Ranillas. Alguna d‚îú¬Æcada m‚îú√≠s tarde, un gran evento expositivo se termin‚îú‚îÇ de llevar por delante la tradicional huerta. Fuente visual: amable aportaci‚îú‚îÇn personal de Pablo Vald‚îú¬Æs.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.66025800, -0.88142600, '0101000020E6100000D6027B4CA434ECBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27263779605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27263779605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27263779605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25417, 'Pasarela Ebro 1945', 'Imagen de la Pasarela Peatonal del Ebro. Se construy‚îú‚îÇ en 1941, y comenz‚îú‚îÇ a dar servicio en febrero de 1942, como forma de comunicar las dos riberas, entre el puente de las piedras, y el puente del ferrocarril.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15748629947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15748629947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15748629947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25431, 'Pasarela de Macanaz a‚îú‚ñíos 40', 'Foto: Miguel Mar‚îú¬°n Chivite. Vista de la pasarela sobre el Ebro tomada desde la arboleda de Macanaz. Adem‚îú√≠s del Torre‚îú‚îÇn de la Zuda, podemos ver los edificios del paseo Echegaray y Caballero. Fuente: Archivo Heraldo de Arag‚îú‚îÇn.', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21549406816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21549406816.webp', 'https://www.flickr.com/photos/zaragozaantigua/21549406816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25432, 'Pasarela Ebro c.1957', 'Imagen capturada en altura, desde el inmediato torre‚îú‚îÇn de la Zuda, de la moderna pasarela peatonal para cruce en seco del r‚îú¬°o Ebro, entre la densa arboleda de Macanaz, al fondo, y la confluencia del paseo de Echegaray y Caballero y la V‚îú¬°a Imperial, antigua calle de Antonio P‚îú¬Ærez, en primer plano, donde la taquilla de peaje. A la izquierda, humea la chimenea fabril de "Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs". Fuente visual: Teodoro Naranjo Dom‚îú¬°nguez, para ABC.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392641973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392641973.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392641973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25443, 'Pasarela del Ebro 1945', 'Imagen con el sonriente posado de varios oficiales del ej‚îú¬Ærcito de tierra (posiblemente, tenientes), en la pasarela peatonal recientemente tendida sobre el Ebro. Al fondo, el Pilar, y la nov‚îú¬°sima y enorme Hospeder‚îú¬°a del Pilar, cuyas dependencias se abren a tres fachadas, y con tres patios interiores. A su izquierda, m‚îú√≠s tarde, se construir‚îú¬°a el edificio de las viviendas del Cabildo, y la nueva Casa de Infantes. A la derecha, fuera de plano, la iglesia de San Juan de los Panetes, y el antiguo embarcadero que, con la entrada en servicio de la pasarela, qued‚îú‚îÇ obsoleto. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901004865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901004865.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901004865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25447, 'R‚îú¬°o Ebro 1921', 'Dibujo del arquitecto Antonio Seti‚îú¬Æn, realizado en Hernani en 1921. Ofrece un proyecto de navegabilidad del r‚îú¬°o Ebro, con un puente colgante. A la izquierda, c‚îú‚ïëpulas y torre del Pilar. En la margen izquierda, un gran parque en los terrenos del futuro Club de Nataci‚îú‚îÇn Helios. Fuente visual: Revista Relieves, n‚îú‚ïëm. 2, 1933.', 1921, 1921, 1921, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65843000, -0.88077700, '0101000020E61000002F35423F532FECBF475A2A6F47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32425819744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32425819744.webp', 'https://www.flickr.com/photos/zaragozaantigua/32425819744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25457, 'Pasarela de Macanaz 1949', 'Dibujo incluido en un art‚îú¬°culo referido a "La arquitectura de Zaragoza en estos ‚îú‚ïëltimos a‚îú‚ñíos", y justificado por la presencia de la pasarela de Macanaz, inaugurada en 1941. Bajo ella se representa la tradicional pr‚îú√≠ctica del transporte de maderas por el r‚îú¬°o Ebro, si bien en esta l‚îú√≠mina la conducci‚îú‚îÇn recae en embarcaciones a motor. Esta actividad fue realizada, entre otras cosas, hasta que la construcci‚îú‚îÇn del embalse de Yesa cerr‚îú‚îÇ el paso a los almadieros del valle del Roncal, que hasta aqu‚îú¬° descend‚îú¬°an sus troncos. Tras la pasarela y en la margen derecha, el templo del Pilar y la tambi‚îú¬Æn reciente y hom‚îú‚îÇnima Hospeder‚îú¬°a. Al fondo, el puente de Piedra. A la izquierda y en primer t‚îú¬Ærmino, un par de jubilados sentados en la arboleda de Macanaz contemplan la escena.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50010448192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50010448192.webp', 'https://www.flickr.com/photos/zaragozaantigua/50010448192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
